   164→    Schema<?> resourceSchema = new ObjectSchema();
   165→    resourceSchema.setSpecVersion(SpecVersion.V31);
   166→    resourceSchema.setName(this.name);
   167→    resourceSchema.setDescription(this.classDescription);
