   184→  private SchemaVisitor createSchemaVisitor(OWLClass analyzedClass) {
   185→    OWLDataFactory dataFactory = context.getManager().getOWLDataFactory();
   186→    OWLClass owlThing = dataFactory.getOWLThing();
