   204→    OWLOntology ontology = context.getOntology();
   205→    return new AxiomCollection(
   206→        getTaxonomyAxioms(analyzedClass),
   207→        ontology.subClassAxiomsForSubClass(analyzedClass).toList(),
   208→        getSuperClassAxioms(analyzedClass, null).toList());
