   252→   * @return the matching OWLDataProperty, or empty if not found
   253→   */
   254→  private Optional<OWLDataProperty> findDataProperty(String propertyName) {
   255→    return context.getOntology()
   256→        .getDataPropertiesInSignature().stream()
   257→        .filter(prop -> nameResolver.resolve(prop).equals(propertyName))
   258→        .findFirst();
   259→  }
   260→
   261→  /**
   262→   * Finds an object property in the ontology by its resolved name.
   263→   *
   264→   * @param propertyName the short-form property name (e.g., "hasAddress")
   265→   * @return the matching OWLObjectProperty, or empty if not found
   266→   */
   267→  private Optional<OWLObjectProperty> findObjectProperty(String propertyName) {
   268→    return context.getOntology()
   269→        .getObjectPropertiesInSignature().stream()
   270→        .filter(prop -> nameResolver.resolve(prop).equals(propertyName))
   271→        .findFirst();
   272→  }
   273→
   274→  /**
   275→   * Extracts range type/class names for a property from multiple sources.
   276→   *
   277→   * <p>Ranges are collected from:
   278→   * <ol>
