   292→    List<String> ranges = new ArrayList<>();
   293→
   294→    // Extract from visitor's range multimap
   295→    rangesFromVisitor.get(propertyName).stream()
   296→        .map(nameResolver::resolve)
   297→        .forEach(ranges::add);
   298→
   299→    // Also extract from restrictions themselves
   300→    Set<RestrictionInfo> propertyRestrictions = restrictions.getOrDefault(propertyName, Set.of());
   301→    propertyRestrictions.stream()
   302→        .flatMap(r -> r.getRangeNames(nameResolver).stream())
   303→        .forEach(ranges::add);
   304→
   305→    // Remove duplicates to avoid treating single-range properties as multi-range
   306→    return ranges.stream().distinct().toList();
