   344→   *   <li>Looks up the OWLDataProperty in the ontology</li>
   345→   *   <li>Extracts description, label, example, ranges, and enum values</li>
   346→   *   <li>Creates a DataPropertyMapper to generate the schema</li>
   347→   *   <li>Adds the property to the resource schema</li>
   348→   *   <li>Marks as required if restrictions indicate requiredness</li>
   349→   * </ol>
   350→   *
   351→   * @param schema the resource schema to add properties to
   352→   * @param visitor visitor containing collected property information
   353→   * @param restrictions restrictions map
   354→   * @param subClassAxioms axioms for extracting example annotations
   355→   */
   356→  private void processDataProperties(
   357→      Schema<?> schema,
   358→      SchemaVisitor visitor,
   359→      Map<String, Set<RestrictionInfo>> restrictions,
   360→      List<OWLSubClassOfAxiom> subClassAxioms) {
   361→
   362→    Multimap<String, OWLDatatype> dataPropertyRanges = visitor.getDataPropertyRanges();
   363→    Set<String> dataPropertyNames = visitor.getDataPropertyNames();
   364→
   365→    for (String propertyName : dataPropertyNames) {
   366→      Optional<OWLDataProperty> dataPropertyOpt = findDataProperty(propertyName);
   367→      if (dataPropertyOpt.isEmpty()) {
   368→        continue;
   369→      }
   370→
   371→      OWLDataProperty dataProperty = dataPropertyOpt.get();
   372→      Set<RestrictionInfo> propertyRestrictions = restrictions.getOrDefault(propertyName, Set.of());
   373→
   374→      String propertyDescription = OntologyUtil.getDescription(dataProperty, context.getOntology());
   375→      String label = getLabel(dataProperty);
   376→      String exampleValue = extractExampleValue(dataProperty, subClassAxioms);
   377→      List<String> rangeTypes = extractPropertyRanges(propertyName, dataPropertyRanges, restrictions);
   378→      List<String> enumValues = propertyRestrictions.stream()
   379→          .flatMap(r -> r.getEnumValues().stream())
   380→          .toList();
   381→
   382→      DataPropertyMapper mapper = new DataPropertyMapper(
   383→          context.getConfig(),
   384→          nameResolver.resolve(dataProperty),
   385→          label,
   386→          propertyDescription,
   387→          exampleValue,
   388→          propertyRestrictions,
   389→          enumValues,
   390→          rangeTypes);
   391→
   392→      try {
   393→        schema.addProperty(mapper.getName(), mapper.getSchemaByDataProperty());
   394→        if (mapper.isRequired()) {
   395→          schema.addRequiredItem(mapper.getName());
   396→        }
   397→      } catch (Exception e) {
   398→        throw new RuntimeException("Error when processing data property " + mapper.getName(), e);
   399→      }
   400→    }
   401→  }
   402→
   403→  /**
   404→   * Processes all object properties and adds them to the schema.
   405→   *
   406→   * <p>For each object property discovered by the SchemaVisitor:
   407→   * <ol>
   408→   *   <li>Looks up the OWLObjectProperty in the ontology</li>
   409→   *   <li>Extracts description, label, and range classes</li>
   410→   *   <li>Creates an ObjectPropertyMapper to generate the schema</li>
   411→   *   <li>Adds the property to the resource schema</li>
   412→   *   <li>Marks as required if restrictions indicate requiredness</li>
   413→   * </ol>
   414→   *
   415→   * @param schema the resource schema to add properties to
   416→   * @param visitor visitor containing collected property information
   417→   * @param restrictions restrictions map
   418→   */
   419→  private void processObjectProperties(
   420→      Schema<?> schema,
   421→      SchemaVisitor visitor,
   422→      Map<String, Set<RestrictionInfo>> restrictions) {
   423→
   424→    Multimap<String, OWLClass> objectPropertyRanges = visitor.getObjectPropertyRanges();
   425→    Set<String> objectPropertyNames = visitor.getObjectPropertyNames();
   426→
   427→    for (String propertyName : objectPropertyNames) {
   428→      Optional<OWLObjectProperty> objectPropertyOpt = findObjectProperty(propertyName);
   429→      if (objectPropertyOpt.isEmpty()) {
   430→        continue;
   431→      }
   432→
   433→      OWLObjectProperty objectProperty = objectPropertyOpt.get();
   434→      Set<RestrictionInfo> propertyRestrictions = restrictions.getOrDefault(propertyName, Set.of());
   435→
   436→      String propertyDescription = OntologyUtil.getDescription(objectProperty, context.getOntology());
   437→      String propertyLabel = getLabel(objectProperty);
   438→      List<String> rangeClasses = extractPropertyRanges(propertyName, objectPropertyRanges, restrictions);
   439→
   440→      ObjectPropertyMapper mapper = new ObjectPropertyMapper(
   441→          context, propertyName, propertyLabel, propertyDescription, propertyRestrictions, rangeClasses);
   442→
   443→      schema.addProperty(mapper.getName(), mapper.getSchema());
   444→      if (mapper.isRequired()) {
   445→        schema.addRequiredItem(mapper.getName());
   446→      }
   447→    }
   448→  }
