    43→public class AsgUtils {
    44→  private static final Logger logger = Logger.getLogger(AsgUtils.class.getName());
    45→
    46→  public static final String[] POSSIBLE_VOCAB_SERIALIZATIONS = {"application/rdf+xml", "text/turtle", "text/n3",
    47→      "application/ld+json"};
    48→
    49→  /**
    50→   * Method that will download an ontology given its URI, doing content negotiation The ontology
    51→   * will be downloaded in the first serialization available (see
    52→   * Constants.POSSIBLE_VOCAB_SERIALIZATIONS)
    53→   *
    54→   * @param uri          the URI of the ontology
    55→   * @param downloadPath path where the ontology will be saved locally.
    56→   */
    57→  public static void downloadOntology(URI uri, String downloadPath) {
    58→    for (String serialization : POSSIBLE_VOCAB_SERIALIZATIONS) {
    59→      logger.info("Attempting to download vocabulary in " + serialization);
    60→      try {
    61→        HttpURLConnection connection = (HttpURLConnection) uri.toURL().openConnection();
    62→        connection.setRequestMethod("GET");
    63→        connection.setInstanceFollowRedirects(true);
    64→        connection.setRequestProperty("Accept", serialization);
    65→        int status = connection.getResponseCode();
    66→        boolean redirect = false;
    67→        if (status != HttpURLConnection.HTTP_OK) {
    68→          if (status == HttpURLConnection.HTTP_MOVED_TEMP || status == HttpURLConnection.HTTP_MOVED_PERM || status == HttpURLConnection.HTTP_SEE_OTHER)
    69→            redirect = true;
    70→        }
    71→        // there are some vocabularies with multiple redirections:
    72→        // 301 -> 303 -> owl
    73→        while (redirect) {
    74→          String newUrl = connection.getHeaderField("Location");
    75→          connection = (HttpURLConnection) new URI(newUrl).toURL().openConnection();
    76→          connection.setRequestProperty("Accept", serialization);
    77→          status = connection.getResponseCode();
    78→          if (status != HttpURLConnection.HTTP_MOVED_TEMP && status != HttpURLConnection.HTTP_MOVED_PERM && status != HttpURLConnection.HTTP_SEE_OTHER)
    79→            redirect = false;
    80→        }
    81→        InputStream in = connection.getInputStream();
    82→        Files.copy(in, Paths.get(downloadPath), StandardCopyOption.REPLACE_EXISTING);
    83→        in.close();
    84→        break; // if the vocabulary is downloaded, then we don't download it for the other
    85→        // serializations
    86→      } catch (IOException e) {
    87→
    88→        throw new RuntimeException("Failed to download vocabulary in RDF format [" + serialization + "]: ", e);
    89→      } catch (URISyntaxException e) {
    90→        throw new RuntimeException(e);
    91→      }
    92→    }
    93→  }
    94→
    95→  /**
    96→   * Given a sample uri return (up to 5) alternatives closely matching it from candidate collection
    97→   *
    98→   * @param sample string that failed some test
    99→   * @param candidates possible candidates that might have been meant
   100→   * @param limit      or null for default 5
   101→   * @return up to limit closest matching candidates
   102→   */
   103→  public static String[] doYouMean(String sample, Collection<String> candidates, @Nullable Integer limit) {
   104→    return candidates.stream()
   105→        .map((candidate) -> ImmutablePair.of(StringUtils.getLevenshteinDistance(candidate, sample), candidate))
   106→        .sorted((p1, p2) -> p1.left - p2.left).limit(Optional.ofNullable(limit).orElse(5)).map(p -> p.right)
   107→        .toArray(String[]::new);
   108→
   109→  }
   110→
   111→  record InvertablePattern(boolean invert, Pattern pattern) {
   112→
   113→    static InvertablePattern fromMapping(String s) {
   114→      return s.length() > 1 && s.startsWith("!") ? new InvertablePattern(true,
   115→          Pattern.compile(s.substring(1))) : new InvertablePattern(false, Pattern.compile(s));
   116→    }
   117→
   118→  }
   119→
   120→  /**
   121→   * @param manager            container of ontologies to apply mappings to
   122→   * @param configuredMappings map of lists of namespace regexps to be mapped to destination namespace. If destination namespace
   123→   *                           is NamespaceMappingsDeserializer.DEFAULT_KEY it will be replace with the first defined default document base iri
   124→   */
   125→  public static void applyNamespaceMappings(OWLOntologyManager manager,
   126→      Map<String, Set<String>> configuredMappings) {
   127→    Optional<String> defaultIri = manager.ontologies()
   128→        .map(owlOntology -> owlOntology.getOntologyID().getDefaultDocumentIRI())
   129→        .flatMap(Optional::stream).findFirst().map(Objects::toString);
   130→    final OWLEntityURIConverter entityConverter = new OWLEntityURIConverter(manager, manager.ontologies()
   131→        .toList(), new OWLEntityURIConverterStrategy() {
   132→      // Expand map of lists to 1:1 source->dest namespace map for easy lookup
   133→      final List<Pair<InvertablePattern, String>> namespacePatternMappings = Optional.ofNullable(
   134→              configuredMappings)
   135→          .map(mappings -> mappings.entrySet().stream().flatMap(stringListEntry -> stringListEntry.getValue().stream()
   136→                  .map(s -> Pair.of(InvertablePattern.fromMapping(s),
   137→                      stringListEntry.getKey().equals(NamespaceMappingsDeserializer.DEFAULT_NS)
   138→                          ? defaultIri.orElseThrow() : stringListEntry.getKey())))
   139→              .toList())
   140→          .orElse(Collections.emptyList());
   141→      final Map<String, Function<IRI, IRI>> mappedNamespaces = new HashMap<>();
   142→
   143→      /**
   144→       * If the entity has an IRI, see if there is a namespace mapping in the config and return mapped version
   145→       * otherwise return unchanged iri (or null)
   146→       * @param owlEntity the entity to convert
   147→       * @return possibly mapped iri
   148→       */
   149→      @Override
   150→      public IRI getConvertedIRI(@Nonnull OWLEntity owlEntity) {
   151→        final IRI entityIRI = owlEntity.getIRI();
   152→        return Optional.of(mappedNamespaces.computeIfAbsent(entityIRI.getNamespace(),
   153→                // Haven't mapped this before - find the first regexp that matches this namespace, if any
   154→                s -> namespacePatternMappings.stream()
   155→                    .filter(patternStringPair -> patternStringPair.getLeft().pattern.asPredicate()
   156→                        .test(s)).findFirst().filter(pair -> !pair.getLeft().invert)
   157→                    .map(pair -> {
   158→                      return (Function<IRI, IRI>) (iri) -> IRI.create(pair.getRight(),
   159→                          iri.getRemainder().orElse(null));
   160→                    })
   161→                    .orElse(Function.identity())))
   162→            .map(mapper -> mapper.apply(entityIRI)).orElse(entityIRI);
   163→      }
   164→    });
   165→    // Commit changes to ontologies
   166→    final List<OWLOntologyChange> changes = entityConverter.getChanges();
   167→    logger.info("Remapped " + changes.size() / 2 + " IRIs");
   168→    manager.applyChanges(changes);
   169→  }
