    10→import com.grl.component.schema.RestrictionInfo;
    11→import io.swagger.v3.oas.models.media.ArraySchema;
    12→import io.swagger.v3.oas.models.media.ComposedSchema;
    13→import io.swagger.v3.oas.models.media.ObjectSchema;
    14→import io.swagger.v3.oas.models.media.Schema;
