    18→public class PropertyNameResolver {
    19→
    20→  private final IRIShortFormProvider shortFormProvider;
    21→
    22→  public PropertyNameResolver() {
    23→    this(new SimpleIRIShortFormProvider());
    24→  }
    25→
    26→  public PropertyNameResolver(IRIShortFormProvider shortFormProvider) {
    27→    this.shortFormProvider = Objects.requireNonNull(shortFormProvider,
    28→        "shortFormProvider must not be null");
    29→  }
    30→
    31→  /**
    32→   * Resolves the short form name of an OWL object property.
    33→   *
    34→   * @param property the OWL object property
    35→   * @return the short form name, never null
    36→   * @throws NullPointerException if property is null
    37→   */
    38→  public String resolve(OWLObjectProperty property) {
    39→    Objects.requireNonNull(property, "property must not be null");
    40→    return resolve(property.getIRI());
    41→  }
    42→
    43→  /**
    44→   * Resolves the short form name of an OWL data property.
    45→   *
    46→   * @param property the OWL data property
    47→   * @return the short form name, never null
    48→   * @throws NullPointerException if property is null
    49→   */
    50→  public String resolve(OWLDataProperty property) {
    51→    Objects.requireNonNull(property, "property must not be null");
    52→    return resolve(property.getIRI());
    53→  }
    54→
    55→  /**
    56→   * Resolves the short form name of an OWL class.
    57→   *
    58→   * @param owlClass the OWL class
    59→   * @return the short form name, never null
    60→   * @throws NullPointerException if owlClass is null
