package com.grl.component.mapper;

import com.grl.component.asg.configuration.YamlConfig;
import com.grl.component.owl.OntologyUtil;
import io.swagger.v3.oas.models.media.Schema;
import java.util.Collections;
import java.util.HashSet;
import java.util.Map;
import java.util.Set;
import java.util.concurrent.ConcurrentSkipListMap;
import org.semanticweb.owlapi.apibinding.OWLManager;
import org.semanticweb.owlapi.model.IRI;
import org.semanticweb.owlapi.model.OWLClass;
import org.semanticweb.owlapi.model.OWLOntology;
import org.semanticweb.owlapi.model.OWLOntologyManager;

public class MappingContext {
  private final String defaultOntologyPrefixIRI;
  private final OWLOntology ontology;
  private final OWLOntologyManager manager = OWLManager.createOWLOntologyManager();

  private final Map<String, Schema<?>> schemaByRef = new ConcurrentSkipListMap<>(); // so we can safely computeIfAbsent
  private final Set<String> computing = new HashSet<>();
  private final String schemaLabel;

  private final OWLClass apiRootClass;

  private final Set<OWLClass> resourceClasses;

  private final YamlConfig config;

  public MappingContext(String defaultOntologyPrefixIRI, OWLOntology ontology, String schemaLabel,
                        OWLClass apiRootClass, Set<OWLClass> resourceClasses, YamlConfig config) {
    this.defaultOntologyPrefixIRI = defaultOntologyPrefixIRI;
    this.ontology = ontology;
    this.schemaLabel = schemaLabel;
    this.apiRootClass = apiRootClass;
    this.resourceClasses = Collections.unmodifiableSet(resourceClasses);
    this.config = config;
  }

  public YamlConfig getConfig() {
    return config;
  }

  public OWLClass getApiRootClass() {
    return apiRootClass;
  }

  public String getDefaultOntologyPrefixIRI() {
    return defaultOntologyPrefixIRI;
  }

  public OWLOntology getOntology() {
    return ontology;
  }


  public String getSchemaLabel() {
    return schemaLabel;
  }

  public Map<String, Schema<?>> getSchemaByRef() {
    return schemaByRef;
  }

  public OWLOntologyManager getManager() {
    return manager;
  }


  /**
   * If not in context cache already, create schema for given class and add to cache
   *
   * @param shortName shortname of class
   */
  public void addSchema(String shortName) {
    schemaByRef.computeIfAbsent(shortName, s -> {
      if (!computing.contains(s)) {
        computing.add(s);
        try {
          OWLClass cls = manager.getOWLDataFactory().getOWLClass(IRI.create(defaultOntologyPrefixIRI + shortName));
          String description = OntologyUtil.getDescription(cls, ontology);
          ResourceSchemaMapper resourceSchemaMapper = new ResourceSchemaMapper(this, cls, description);
          return resourceSchemaMapper.getSchema();
        } finally {
          computing.remove(s);
        }
      } else
        return null; // already being computed, ignore to avoid infinite recursion
    });
  }

  public Set<OWLClass> getResourceClasses() {
    return resourceClasses;
  }

  /**
   * Returns the maximum depth for expanding object property assertions on Pattern B taxonomy
   * individuals.
   *
   * @return the maximum individual depth from config
   */
  public int getMaxIndividualDepth() {
    return config.getMaxIndividualDepth();
  }
}

