package com.grl.component.mapper;

import static com.grl.component.asg.configuration.NamespaceMappingsDeserializer.DEFAULT_NS;

import com.fasterxml.jackson.annotation.JsonInclude.Include;
import com.fasterxml.jackson.core.JsonProcessingException;
import com.fasterxml.jackson.databind.ObjectMapper;
import com.google.common.collect.SetMultimap;
import com.grl.component.asg.AsgUtils;
import com.grl.component.asg.OntologyConstants;
