import io.swagger.v3.oas.models.media.Content;
import io.swagger.v3.oas.models.media.IntegerSchema;
import io.swagger.v3.oas.models.media.MediaType;
import io.swagger.v3.oas.models.media.ObjectSchema;
import io.swagger.v3.oas.models.media.Schema;
import io.swagger.v3.oas.models.media.StringSchema;
import io.swagger.v3.oas.models.parameters.Parameter;
import io.swagger.v3.oas.models.parameters.RequestBody;
import io.swagger.v3.oas.models.responses.ApiResponse;
import io.swagger.v3.oas.models.security.SecurityRequirement;
import io.swagger.v3.oas.models.tags.Tag;
import java.io.FileOutputStream;
import java.io.IOException;
import java.net.URI;
import java.nio.file.Path;
import java.util.Collection;
import java.util.Collections;
import java.util.LinkedHashMap;
import java.util.List;
import java.util.Map;
import java.util.Objects;
import java.util.Optional;
import java.util.Set;
import java.util.logging.Logger;
import java.util.regex.Pattern;
import java.util.stream.Collectors;
import java.util.stream.Stream;
import org.apache.commons.lang3.StringUtils;
import org.apache.commons.text.StringSubstitutor;
import org.protege.xmlcatalog.owlapi.XMLCatalogIRIMapper;
import org.semanticweb.owlapi.apibinding.OWLManager;
import org.semanticweb.owlapi.model.HasFiller;
import org.semanticweb.owlapi.model.HasProperty;
import org.semanticweb.owlapi.model.IRI;
import org.semanticweb.owlapi.model.OWLClass;
import org.semanticweb.owlapi.model.OWLOntology;
import org.semanticweb.owlapi.model.OWLOntologyCreationException;
import org.semanticweb.owlapi.model.OWLOntologyManager;
import org.semanticweb.owlapi.model.OWLOntologyStorageException;
import org.semanticweb.owlapi.model.OWLQuantifiedObjectRestriction;
import org.semanticweb.owlapi.model.OWLSubClassOfAxiom;
import org.semanticweb.owlapi.search.EntitySearcher;
import org.semanticweb.owlapi.util.OWLOntologyMerger;

public class OntologyMapper {

  private final static Logger logger = Logger.getLogger(OntologyMapper.class.getName());
  private static final String FLATTENED_FILENAME = "ontology-flat.owl";
  private static final String MERGED_FILENAME = "ontology-merged.owl";
  private static final Pattern OAUTH_SCOPE_PATTERN = Pattern.compile("^[\\x21\\x23-\\x5B\\x5D-\\x7E]+$"); // https://datatracker.ietf.org/doc/html/rfc6749#section-3.3
  private final PropertyNameResolver nameResolver = new PropertyNameResolver();
  private final YamlConfig config;
  private final OWLOntologyManager manager;
  private final OWLOntology ontology;
  private final OpenAPI openApi;

  private MappingContext context;

  public OntologyMapper(YamlConfig config) {
    this.config = Objects.requireNonNull(config);
    this.manager = OWLManager.createOWLOntologyManager();
    this.ontology = loadOntologies();
    this.openApi = deepCopy(config.getTemplates().getOpenapi(), OpenAPI.class);
  }

  /**
   * Load ontologies specified in config into manager member
   * <ul>
   *   <li>Merges into a single ontology (saves result as MERGED_FILENAME)</li>
   *    <li>Flattens namespaces according to rules in config (saves result as @see FLATTENED_FILENAME)</li>
   * </ul>
   * on exit manager will be initialized with this ontology
   */
  private OWLOntology loadOntologies() {
    try {
      OWLOntologyManager loadingManager = OWLManager.createOWLOntologyManager();
      if (null != config.getCatalogFile()) {
        try {
          loadingManager.getIRIMappers().add(new XMLCatalogIRIMapper(config.getCatalogFile().toFile()));
        } catch (IOException e) {
          logger.warning("Bad catalog file, ignoring: " + e.getLocalizedMessage());
        }
      }

      // Load the ontology into the manager
      Map<String, OWLOntology> ontologyByPath = AsgUtils.downloadOntologies(loadingManager, config.getOntologies(),
          config.getApiOutputDir());

      // merge all ontologies into a single namespace
      final OWLOntologyManager flattenedManager = OWLManager.createOWLOntologyManager();
      final OWLOntology target = new OWLOntologyMerger(loadingManager).createMergedOntology(flattenedManager,
          ontologyByPath.values()
          .stream().findFirst().orElseThrow().getOntologyID().getOntologyIRI().orElseThrow());

      // Save merged ontologies to a flat ontology file
      Path mergedOntologyPath = config.getApiOutputDir().resolve(MERGED_FILENAME);
      flattenedManager.saveOntology(target, new FileOutputStream(mergedOntologyPath.toFile()));

      // And reload from there into a new manager (problems with Document IRI unless loaded from file)
      AsgUtils.downloadOntologies(this.manager, List.of(URI.create(mergedOntologyPath.toString())),
          config.getApiOutputDir());
      if (this.manager.ontologies().count() == 1)
        logger.info("Ontologies merged");
      else
        throw new RuntimeException("Single resultant ontology expected");

      // Apply any namespace mappings in config
      Optional.ofNullable(config.getNamespaceMappings())
          .ifPresent(configMappings -> AsgUtils.applyNamespaceMappings(manager, configMappings));

      // Save a copy for reference
      OWLOntology result = this.manager.ontologies().findFirst().orElseThrow();
      manager.saveOntology(result, new FileOutputStream(config.getApiOutputDir().resolve(FLATTENED_FILENAME).toFile()));

      return result;
    } catch (OWLOntologyStorageException | IOException | OWLOntologyCreationException e) {
      throw new RuntimeException("Unable to create flattened/merged ontology", e);
    }

  }

  public static OpenAPI map(YamlConfig config) {
    return new OntologyMapper(config).mapApiRoot();
  }

  private OpenAPI mapApiRoot() {
    String defaultIRIPrefix = Objects.requireNonNull(ontology.getFormat()).asPrefixOWLDocumentFormat()
        .getDefaultPrefix();
    // List of classes marked with APIRoot subclass
    Set<OWLClass> apiRootClasses = ontology.getSubClassAxiomsForSubClass(manager.getOWLDataFactory()
            .getOWLClass(IRI.create(defaultIRIPrefix, OntologyConstants.apiRoot))).stream()
        .map(OWLSubClassOfAxiom::getSuperClass).flatMap(Narrow.to(OWLQuantifiedObjectRestriction.class))
        .filter(objectRestriction -> nameResolver.resolve(
                objectRestriction.getProperty().asOWLObjectProperty())
            .equals(OntologyConstants.hasAPI)).map(objectRestriction -> objectRestriction.getFiller().asOWLClass())
        .collect(Collectors.toSet());

    // Find intended root class...
    OWLClass apiRootClass = config.getRootClass() != null ?
        // It is specified in config, but must be marked with ApiRoot
        apiRootClasses.stream().filter(WithIRI.of(IRI.create(config.getRootClass()).getShortForm())).findFirst()
            .orElseThrow(() -> new RuntimeException("Not related to APIRoot: " + config.getRootClass()))
        // otherwise if there's a single APIRoot assume that
        : apiRootClasses.stream().reduce((a, b) -> {
      throw new RuntimeException("No valid rootClass defined in config, and cannot infer from APIRoot class " +
          "which has multiple API subclasses. Set rootClass to one of:\n" + String.join("\n", apiRootClasses.stream()
          .map(OWLClass::getIRI).toList()));

    }).orElseThrow(() -> new RuntimeException("Unable to ascertain root class for API"));

    // This will be used to match all objects/properties in the schema with annotations
    String schemaLabel = nameResolver.resolve(apiRootClass);
    logger.info("API will be inferred from items annotated with apiLabel of " + schemaLabel);

    // Set the overall api title
    Info info = Optional.ofNullable(openApi.getInfo()).orElse(new Info());
    info.setTitle(OntologyUtil.getTitle(apiRootClass, ontology));

    // Save this value as extension for Graph tool usage whan filtering for API-specific data
    info.addExtension(OpenApiConstants.X_GRL_API_LABEL, schemaLabel);

    // Add extension for namespace if namespace mapping present
    Optional.ofNullable(config.getNamespaceMappings())
        .flatMap(stringSetMap -> stringSetMap.keySet().stream().findFirst())
        .ifPresent(s -> info.addExtension(OpenApiConstants.X_GRL_GRAPH_NAMESPACE,
            s.equals(DEFAULT_NS) ? defaultIRIPrefix : s));

    openApi.info(info);

    openApi.paths(Optional.ofNullable(openApi.getPaths()).orElse(new Paths()))
        .components(Optional.ofNullable(openApi.getComponents()).orElse(new Components()));

    Set<OWLClass> resourceClasses = EntitySearcher.getSuperClasses(apiRootClass, ontology)
        .flatMap(Narrow.to(OWLQuantifiedObjectRestriction.class))
        .filter(WithIRI.onPropertyOf(OntologyConstants.hasResourceSchema)).map(HasFiller::getFiller)
        .flatMap(Narrow.to(OWLClass.class)).filter(cls -> {
          boolean hasApiId = EntitySearcher.getSuperClasses(cls, ontology).flatMap(Narrow.to(HasProperty.class))
              .anyMatch(WithIRI.onPropertyOf(OntologyConstants.apiID));
          if (!hasApiId)
            logger.warning(cls + " is marked as hasResourceSchema for " + apiRootClass + " but does not have an " +
                "apiID" + " property and will not be added to the API");
          return hasApiId;
        }).collect(Collectors.toSet());

    // Create long-lived context for this mapping
    context = new MappingContext(defaultIRIPrefix, ontology, Objects.requireNonNull(schemaLabel), apiRootClass,
        resourceClasses, config);

    resourceClasses.forEach(this::mapToPathItems);

    return openApi;
  }

  private void mapToPathItems(OWLClass resourceClass) {
    String name = nameResolver.resolve(resourceClass);
    SetMultimap<String, String> annotations = OntologyUtil.annotationsOf(resourceClass, ontology);
    String prefLabel = StringUtils.defaultIfBlank(String.join(",", annotations.get("prefLabel")),
        name);
    String definition = OntologyUtil.getDescription(resourceClass, ontology);
    PathItem singlePath = deepCopy(config.getTemplates().getSinglePathItem(), PathItem.class);
    singlePath.setSummary("Single " + StringUtils.defaultIfBlank(prefLabel, name));
    singlePath.setDescription(definition);
    String parameterName = name + "Id";
    openApi.addTagsItem(new Tag().name(name).description(definition));
    Content resourceContent = new Content().addMediaType("application/json",
        new MediaType().schema(new ComposedSchema().$ref(name)));
    final Set<String> security = securityGroupsForResource(resourceClass);
    Stream.of(PathItem.HttpMethod.GET, PathItem.HttpMethod.PUT, PathItem.HttpMethod.PATCH, PathItem.HttpMethod.DELETE)
        .forEach(httpMethod -> {
              Operation defaultOperation = singlePath.readOperationsMap().getOrDefault(httpMethod, new Operation());
          defaultOperation.addParametersItem(new Parameter().name(parameterName).in("path").schema(new StringSchema()))
                  .getResponses()
                  .addApiResponse("200", new ApiResponse().description("Existing " + name).content(resourceContent));
          mapToSecurityItems(name, httpMethod, security).forEach(defaultOperation::addSecurityItem);
            }
        );
    singlePath.getPut().requestBody(new RequestBody().content(resourceContent));
    singlePath.getPatch().requestBody(new RequestBody().content(resourceContent));
    openApi.getPaths().addPathItem("/" + name + "/{" + parameterName + "}", singlePath);

    // Add GET to collection path for fetching list of resources
    PathItem collectionPath = deepCopy(config.getTemplates().getCollectionPathItem(), PathItem.class);
    collectionPath.setSummary("Collection of " + prefLabel);
    collectionPath.setDescription(definition);
    Operation getCollection = collectionPath.readOperationsMap().getOrDefault(PathItem.HttpMethod.GET, new Operation());
    getCollection.addParametersItem(new Parameter().name("start").in("query").description("Index of start item")
            .schema(new IntegerSchema()))
        .addParametersItem(new Parameter().name("limit").in("query").description("Maximum items to return")
            .schema(new IntegerSchema())).getResponses()
        .addApiResponse("200", new ApiResponse().description(name + " Collection")
            .content(new Content().addMediaType("application/json",
                new MediaType().schema(new ObjectSchema().properties(Map.of("totalItems", new IntegerSchema().description("Collection of returned " + name + "items")
                    .example(3), "items", new ArraySchema().items(new ComposedSchema().$ref(name))))))));
    mapToSecurityItems(name, PathItem.HttpMethod.GET, security).forEach(getCollection::addSecurityItem);

    // Add POST to collection path for creating resource
    Operation postCollection = collectionPath.readOperationsMap()
        .getOrDefault(PathItem.HttpMethod.POST, new Operation());
    postCollection.requestBody(new RequestBody().content(resourceContent)).getResponses()
        .addApiResponse("201",
            new ApiResponse().description("New " + name).content(resourceContent));
    mapToSecurityItems(name, PathItem.HttpMethod.POST, security).forEach(postCollection::addSecurityItem);

    mapToComponentSchemas(resourceClass, name, definition);
    openApi.getPaths().addPathItem("/" + name, collectionPath);

    // Tag all operations for this entity for
    singlePath.readOperationsMap()
        .forEach((method, operation) -> operation.addTagsItem(name).operationId(name + "/single/" + method));
    collectionPath.readOperationsMap()
        .forEach((method, operation) -> operation.addTagsItem(name).operationId(name + "/collection/" + method));
  }

  /**
   * Determine the security groups associated with the given resource class. If security annotations are present on the
   * resource class's restriction for this API they are returned, otherwise a default group of the form
   * apiName:resourceName is returned
   *
   * @param resourceClass class representing api resource
   * @return set of groups found
   */
  private Set<String> securityGroupsForResource(OWLClass resourceClass) {
    return ontology.subClassAxiomsForSubClass(context.getApiRootClass())
        .filter(owlSubClassOfAxiom -> owlSubClassOfAxiom.getSuperClass() instanceof OWLQuantifiedObjectRestriction restriction && restriction.getFiller()
            .isOWLClass() && restriction.getFiller().asOWLClass().equals(resourceClass)
            && nameResolver.resolve(restriction.getProperty()
                .asObjectPropertyExpression().getNamedProperty())
            .equals(OntologyConstants.hasResourceSchema)).findFirst()
        .map(owlSubClassOfAxiom -> OntologyUtil.annotationsOf(owlSubClassOfAxiom).get(OntologyConstants.security))
        .orElse(Collections.emptySet());

  }

  /**
   * Return security items, if any, to associate with a method of the given type for a resource. Each security
   * annotation will generate a security requirement in the api spec for each method. Template from
   * config.securityTemplate will be used to generate the security requirement.<br/>
   * If there is no security scheme in effect, or of no groups are given this stream will be empty, and the
   * defaultSecurityTemplate value will be used from the config<br/>
   * security requirements can contain placeholders which will be replaced in the generated openapi spec:
   * {api} the name of the api (config.name)
   * {action} mapped for each http method being generated from the config.securityActionMappings
   * {model} The resource (model) name for each api resource being generated
   * {security} the security string as obtained from the "security" annotation
   *
   * @param name  name of resource being mapped
   * @param method   being mapped
   * @param security groups the resource belongs to
   * @return SecurityItems
   */
  private Stream<SecurityRequirement> mapToSecurityItems(String name, PathItem.HttpMethod method,
                                                         Set<String> security) {
    // If apiKey is enabled, add this as a requirement
    Stream.Builder<SecurityRequirement> requirements = Stream.builder();
    config.getApiKeySecuritySchemaName()
        .ifPresent(s -> requirements.add(new SecurityRequirement().addList(s)));

    // oauth2 scheme - add requirment groups for these
    config.getOAuth2SecuritySchemeName().ifPresent(oauthSchemeName -> {
      String template =
          security.isEmpty() ? config.getDefaultSecurityTemplate() : config.getSecurityTemplate();
      if (StringUtils.isEmpty(template)) {
        // no scoped requirements, auth alone is sufficient
        requirements.add(new SecurityRequirement().addList(oauthSchemeName));
      } else {
        // Map scoped requirements
        Map<String, String> replacements = Map.of("api", config.getName(), // name of api
            "action", config.getSecurityActionMappings()
                .getOrDefault(method, ""), // action, mapped from path's http method,
            "model", name // current path's model/resource
        );
        List<String> securityRequirements =
            Stream.of(security, // multiple security names maye be provided
                    List.of("") // non if default
                ).flatMap(Collection::stream)
                .map(s -> new StringSubstitutor(
                    key -> key.equals("security") ? s : replacements.getOrDefault(key, ""), "{",
                    "}", '\'').setEnableSubstitutionInVariables(
                        true) // security annotations can contain replacements
                    .replace(template)).filter(requirement -> {
                  boolean valid = OAUTH_SCOPE_PATTERN.matcher(requirement).matches();
                  if (!valid) {
                    logger.warning(String.format(
                        "%s (%s) security requirement generated ignored (must match " + "https" +
                            "://datatracker.ietf.org/doc/html/rfc6749#section-3.3 scope_token): %s",
                        name, method, requirement));
                  }
                  return valid;
                }).toList();
        securityRequirements.stream().map(
            securityRequirement -> new SecurityRequirement().addList(oauthSchemeName,
                securityRequirement)).forEach(requirements::add);
      }
    });
    return requirements.build();
  }

  private void mapToComponentSchemas(OWLClass resourceClass, String name, String definition) {

    ResourceSchemaMapper schemaMapper = new ResourceSchemaMapper(context, resourceClass, definition);
    Map<String, Schema> schemas = openApi.getComponents()
        .schemas(Optional.ofNullable(openApi.getComponents().getSchemas()).orElse(new LinkedHashMap<>())).getSchemas();
    schemas.put(name, schemaMapper.getSchema());
    schemas.putAll(context.getSchemaByRef());
  }

  private static <T> T deepCopy(T src, Class<T> cls) {
    ObjectMapper mapper = Json.mapper().setSerializationInclusion(Include.NON_NULL);
    try {
      return mapper.readValue(mapper.writeValueAsString(src), cls);
    } catch (JsonProcessingException e) {
      throw new RuntimeException(e);
    }
  }
}

