   587→  /**
   588→   * Logs a warning when no properties were found for a class.
   589→   *
   590→   * <p>This typically indicates that the ontology is missing apiLabel annotations
   591→   * on the property restrictions, or that the schema label doesn't match.
   592→   *
   593→   * @param analyzedClass the class that had no mappable properties
   594→   * @param axioms all collected axioms (for diagnostic output)
   595→   */
   596→  private void logMissingPropertiesWarning(OWLClass analyzedClass, AxiomCollection axioms) {
   597→    logger.warning("No properties with " + OntologyConstants.apiLabel
   598→        + " annotation found for: " + analyzedClass);
   599→
   600→    List<OWLSubClassOfAxiom> allAxioms = Stream.of(axioms.superClass(), axioms.subClass(), axioms.taxonomy())
   601→        .flatMap(Collection::stream)
   602→        .toList();
   603→
   604→    if (!allAxioms.isEmpty()) {
   605→      allAxioms.stream()
   606→          .map(axiom -> axiom.getSuperClass().toString())
   607→          .forEach(s -> logger.warning("\tPossible property: " + s));
   608→    }
   609→  }
   610→
   611→  private List<OWLSubClassOfAxiom> getTaxonomyAxioms(OWLClass analyzedClass) {
   612→    Set<OWLSubClassOfAxiom> subAx = context.getOntology().getSubClassAxiomsForSubClass(analyzedClass);
   613→    String schemaAnnotation = getSchemaAnnotation(context.getSchemaLabel());
   614→
   615→    return subAx.stream().filter(ax -> ax.annotations()
   616→        .anyMatch(annotation -> annotation.getValue().toString().equals(schemaAnnotation))).filter(ax -> {
   617→      OWLClassExpression superCls = ax.getSuperClass();
   618→      return !superCls.getObjectPropertiesInSignature().isEmpty() && (superCls.individualsInSignature()
   619→          .anyMatch(individual -> !EntitySearcher.getObjectPropertyValues(individual, context.getOntology())
   620→              .isEmpty()) || superCls.classesInSignature()
   621→          .anyMatch(cls -> EntitySearcher.getIndividuals(cls, context.getOntology()).findAny().isPresent()));
   622→    }).collect(Collectors.toList());
   623→  }
   624→
   625→  public String getSchemaName() {
   626→    return nameResolver.resolve(cls);
   627→  }
   628→
   629→  private String getSchemaAnnotation(String schema) {
   630→    return '"' + schema + '"' + "^^xsd:string";
   631→  }
   632→
   633→  private String taxonomyName(String taxonomy_name) {
   634→    if (StringUtils.countMatches(taxonomy_name, "_") > 0) {
   635→      return taxonomy_name.substring(taxonomy_name.lastIndexOf("_") + 1);
   636→    }
   637→    return taxonomy_name.substring(0, 1).toUpperCase() + taxonomy_name.substring(1);
   638→  }
   639→
   640→  private String getLabel(final OWLEntity entity) {
   641→    return OntologyUtil.getTitle(entity, context.getOntology());
   642→  }
   643→
   644→  private Stream<OWLSubClassOfAxiom> getSuperClassAxioms(OWLClass analyzedClass,
   645→                                                         @Nullable Set<OWLClass> ignoreClasses) {
   646→    final Set<OWLClass> processedClasses = Optional.ofNullable(ignoreClasses).orElse(new HashSet<OWLClass>());
   647→    final String schemaAnnotation = getSchemaAnnotation(context.getSchemaLabel());
   648→    return context.getOntology().subClassAxiomsForSubClass(analyzedClass)
   649→        .filter(WithAnnotation.of(OntologyConstants.apiLabel, context.getSchemaLabel()))
   650→        .map(OWLSubClassOfAxiom::getSuperClass).filter(OWLClassExpression::isOWLClass).map(AsOWLClass::asOWLClass)
   651→        .filter(Predicate.not(processedClasses::contains)).peek(processedClasses::add) // side effect
   652→        .flatMap(context.getOntology()::subClassAxiomsForSubClass).flatMap(owlSubClassOfAxiom -> {
   653→          final OWLClassExpression superClass = owlSubClassOfAxiom.getSuperClass();
   654→          final List<OWLSubClassOfAxiom> superClassAxioms = new ArrayList<>();
   655→          if (superClass.isOWLClass()) {
   656→            getSuperClassAxioms(superClass.asOWLClass(), processedClasses).forEach(superClassAxioms::add);
   657→          }
   658→          if (owlSubClassOfAxiom.annotations()
   659→              .anyMatch(owlAnnotation -> owlAnnotation.getValue().toString().equals(schemaAnnotation))) {
   660→            superClassAxioms.add(owlSubClassOfAxiom);
   661→          }
   662→          return superClassAxioms.stream();
   663→        });
   664→  }
   665→
   666→}
