package com.grl.component.mapper;

import com.google.common.collect.Multimap;
import com.grl.component.asg.OntologyConstants;
import com.grl.component.owl.Narrow;
import com.grl.component.owl.OntologyUtil;
import com.grl.component.owl.WithAnnotation;
import com.grl.component.schema.PropertyNameResolver;
import com.grl.component.schema.RestrictionInfo;
import com.grl.component.schema.SchemaVisitor;
import com.grl.component.schema.TaxonomyInfo;
import com.grl.component.schema.TaxonomyPattern;
import io.swagger.v3.oas.models.SpecVersion;
import io.swagger.v3.oas.models.media.ObjectSchema;
import io.swagger.v3.oas.models.media.Schema;
import java.util.ArrayList;
import java.util.Collection;
import java.util.HashSet;
import java.util.LinkedHashSet;
import java.util.List;
import java.util.Map;
import java.util.Optional;
import java.util.Set;
import java.util.function.Predicate;
import java.util.logging.Logger;
import java.util.stream.Collectors;
import java.util.stream.Stream;
import javax.annotation.Nullable;
import org.apache.commons.lang3.StringUtils;
import org.semanticweb.owlapi.model.AsOWLClass;
import org.semanticweb.owlapi.model.OWLClass;
import org.semanticweb.owlapi.model.OWLClassExpression;
import org.semanticweb.owlapi.model.OWLDataFactory;
import org.semanticweb.owlapi.model.OWLDataProperty;
import org.semanticweb.owlapi.model.OWLDataRestriction;
import org.semanticweb.owlapi.model.OWLDatatype;
import org.semanticweb.owlapi.model.OWLEntity;
import org.semanticweb.owlapi.model.OWLLiteral;
import org.semanticweb.owlapi.model.OWLNamedIndividual;
import org.semanticweb.owlapi.model.OWLObjectProperty;
import org.semanticweb.owlapi.model.OWLOntology;
import org.semanticweb.owlapi.model.OWLSubClassOfAxiom;
import org.semanticweb.owlapi.search.EntitySearcher;

/**
 * Maps an OWL class to an OpenAPI Schema object.
 *
 * <p>This mapper analyzes an OWL class from the ontology and generates a corresponding
 * OpenAPI 3.1 ObjectSchema with properties derived from:
 * <ul>
 *   <li><b>Data properties</b> - mapped to primitive schema types (string, integer, etc.)</li>
 *   <li><b>Object properties</b> - mapped to $ref references or inline schemas</li>
 *   <li><b>Taxonomy properties</b> - mapped to enum schemas based on named individuals</li>
 * </ul>
 *
 * <h2>Processing Pipeline</h2>
 * <pre>
 * OWLClass → SchemaVisitor → Axiom Collection → Restriction Collection
 *                                   ↓
 *        ┌────────────────────────────────────────────┐
 *        │                                            │
 *        ▼                    ▼                       ▼
 *  DataPropertyMapper   ObjectPropertyMapper   TaxonomyPropertyMapper
 *        │                    │                       │
 *        └────────────────────┴───────────────────────┘
 *                             ↓
 *                     OpenAPI ObjectSchema
 * </pre>
 *
 * <h2>Annotation Filtering</h2>
 * <p>Only axioms annotated with {@code apiLabel} matching the schema label from
 * {@link MappingContext#getSchemaLabel()} are included in the generated schema.
 *
 * <h2>Thread Safety</h2>
 * <p>This class is <b>not thread-safe</b>. Each instance should be used to map
 * a single OWL class and then discarded.
 *
 * @see DataPropertyMapper
 * @see ObjectPropertyMapper
 * @see TaxonomyPropertyMapper
 * @see SchemaVisitor
 */
public class ResourceSchemaMapper {

  /**
   * Holds categorized axiom collections for the analyzed class.
   *
   * @param taxonomy axioms referencing named individuals (enum values)
   * @param subClass direct SubClassOf axioms for the analyzed class
   * @param superClass inherited axioms from the class hierarchy
   */
  private record AxiomCollection(
      List<OWLSubClassOfAxiom> taxonomy,
      List<OWLSubClassOfAxiom> subClass,
      List<OWLSubClassOfAxiom> superClass) {}
  private static final Logger logger = Logger.getLogger(ResourceSchemaMapper.class.getName());
  private final MappingContext context;
  private final PropertyNameResolver nameResolver = new PropertyNameResolver();
  private final String type;
  private final OWLClass cls;
  private final String classDescription;
  private final String name;
  private final Schema<?> schema;

  public Schema<?> getSchema() {
    return schema;
  }

  public String getName() {
    return name;
  }

  public ResourceSchemaMapper(MappingContext context, OWLClass cls, String clsDescription) {
    this.context = context;
    this.cls = cls;
    this.classDescription = clsDescription;
    this.type = "object";
    this.name = nameResolver.resolve(cls);
    this.schema = createSchema(cls);
  }

  /**
   * Creates the OpenAPI schema for the analyzed OWL class.
   *
   * <p>This method orchestrates the schema generation by:
   * <ol>
   *   <li>Initializing the base ObjectSchema with metadata</li>
   *   <li>Creating a visitor to traverse class restrictions</li>
   *   <li>Collecting relevant axioms from the ontology</li>
   *   <li>Visiting axioms to gather property restrictions</li>
   *   <li>Processing data, object, and taxonomy properties</li>
   * </ol>
   *
   * @param analyzedClass the OWL class to generate a schema for
   * @return the generated OpenAPI Schema object
   */
  private Schema<?> createSchema(OWLClass analyzedClass) {
    Schema<?> schema = initializeResourceSchema();

    SchemaVisitor visitor = createSchemaVisitor(analyzedClass);
    AxiomCollection axioms = collectRelevantAxioms(analyzedClass);

    visitAxioms(visitor, axioms);

    Map<String, Set<RestrictionInfo>> restrictions = visitor.getRestrictions();

    processDataProperties(schema, visitor, restrictions, axioms.subClass());
    processObjectProperties(schema, visitor, restrictions);
    processTaxonomyProperties(schema, axioms.taxonomy(), visitor, restrictions);

    if (schema.getProperties() == null || schema.getProperties().isEmpty()) {
      logMissingPropertiesWarning(analyzedClass, axioms);
    }

    return schema;
  }

  /**
   * Creates and configures the base ObjectSchema with standard properties.
   *
   * @return a new ObjectSchema configured with name, type, description, and OpenAPI 3.1 spec version
   */
  private Schema<?> initializeResourceSchema() {
    Schema<?> resourceSchema = new ObjectSchema();
    resourceSchema.setSpecVersion(SpecVersion.V31);
    resourceSchema.setName(this.name);
    resourceSchema.setDescription(this.classDescription);
    resourceSchema.setType(this.type);
    resourceSchema.setAdditionalProperties(false);
    resourceSchema.setTitle(getLabel(this.cls));
    return resourceSchema;
  }

  /**
   * Creates a SchemaVisitor for analyzing class restrictions.
   *
   * <p>A single visitor collects both object property and data property restrictions,
   * as the OWL visitor dispatch is type-safe and SchemaVisitor internally separates
   * property types.
   *
   * @param analyzedClass the OWL class to analyze
   * @return the configured visitor
   */
  private SchemaVisitor createSchemaVisitor(OWLClass analyzedClass) {
    OWLDataFactory dataFactory = context.getManager().getOWLDataFactory();
    OWLClass owlThing = dataFactory.getOWLThing();
    return new SchemaVisitor(analyzedClass, context.getOntology(), owlThing);
  }

  /**
   * Collects all relevant axioms for the analyzed class from the ontology.
   *
   * <p>Gathers three categories of axioms:
   * <ul>
   *   <li><b>Taxonomy axioms</b>: SubClassOf axioms referencing named individuals (enum values)</li>
   *   <li><b>SubClass axioms</b>: Direct SubClassOf axioms for the analyzed class</li>
   *   <li><b>SuperClass axioms</b>: Inherited axioms from the class hierarchy</li>
   * </ul>
   *
   * @param analyzedClass the OWL class to collect axioms for
   * @return a record containing categorized axiom lists
   */
  private AxiomCollection collectRelevantAxioms(OWLClass analyzedClass) {
    OWLOntology ontology = context.getOntology();
    return new AxiomCollection(
        getTaxonomyAxioms(analyzedClass),
        ontology.subClassAxiomsForSubClass(analyzedClass).toList(),
        getSuperClassAxioms(analyzedClass, null).toList());
  }

  /**
   * Visits axioms with the schema visitor to collect restrictions.
   *
   * <p>For each axiom, the superclass expression is visited by the visitor.
   * The OWL visitor dispatch is type-safe, so a single visitor correctly handles
   * both object and data property restrictions.
   *
   * <p>Taxonomy axioms are also visited to detect taxonomy patterns (A, B, C, D)
   * via SchemaVisitor's taxonomy pattern detector.
   *
   * @param visitor the schema visitor to use
   * @param axioms the axiom collection to process
   */
  private void visitAxioms(SchemaVisitor visitor, AxiomCollection axioms) {
    String schemaLabel = context.getSchemaLabel();

    // Filter axioms to only those annotated with the target apiLabel
    // This allows multiple API schemas to be generated from the same ontology
    axioms.subClass().stream()
        .filter(axiom -> !axioms.taxonomy().contains(axiom))
        .filter(WithAnnotation.of(OntologyConstants.apiLabel, schemaLabel))
        .map(OWLSubClassOfAxiom::getSuperClass)
        .forEach(superClass -> superClass.accept(visitor));

    axioms.superClass().stream()
        .map(OWLSubClassOfAxiom::getSuperClass)
        .forEach(superClass -> superClass.accept(visitor));

    // Also visit taxonomy axioms for pattern detection
    // This enables detectTaxonomyPattern to be called for Pattern B individuals
    axioms.taxonomy().stream()
        .filter(WithAnnotation.of(OntologyConstants.apiLabel, schemaLabel))
        .map(OWLSubClassOfAxiom::getSuperClass)
        .forEach(superClass -> superClass.accept(visitor));
  }


  /**
   * Finds a data property in the ontology by its resolved name.
   *
   * @param propertyName the short-form property name (e.g., "firstName")
   * @return the matching OWLDataProperty, or empty if not found
   */
  private Optional<OWLDataProperty> findDataProperty(String propertyName) {
    return context.getOntology()
        .getDataPropertiesInSignature().stream()
        .filter(prop -> nameResolver.resolve(prop).equals(propertyName))
        .findFirst();
  }

  /**
   * Finds an object property in the ontology by its resolved name.
   *
   * @param propertyName the short-form property name (e.g., "hasAddress")
   * @return the matching OWLObjectProperty, or empty if not found
   */
  private Optional<OWLObjectProperty> findObjectProperty(String propertyName) {
    return context.getOntology()
        .getObjectPropertiesInSignature().stream()
        .filter(prop -> nameResolver.resolve(prop).equals(propertyName))
        .findFirst();
  }

  /**
   * Extracts range type/class names for a property from multiple sources.
   *
   * <p>Ranges are collected from:
   * <ol>
   *   <li>The SchemaVisitor's property range multimap (from restriction fillers)</li>
   *   <li>The RestrictionInfo objects themselves (via getRangeNames)</li>
   * </ol>
   *
   * @param propertyName the property to extract ranges for
   * @param rangesFromVisitor multimap of property → range classes/datatypes from visitor
   * @param restrictions map of property → RestrictionInfo set
   * @return deduplicated list of range type names
   */
  private List<String> extractPropertyRanges(
      String propertyName,
      Multimap<String, ? extends OWLEntity> rangesFromVisitor,
      Map<String, Set<RestrictionInfo>> restrictions) {
    List<String> ranges = new ArrayList<>();

    // Extract from visitor's range multimap
    rangesFromVisitor.get(propertyName).stream()
        .map(nameResolver::resolve)
        .forEach(ranges::add);

    // Also extract from restrictions themselves
    Set<RestrictionInfo> propertyRestrictions = restrictions.getOrDefault(propertyName, Set.of());
    propertyRestrictions.stream()
        .flatMap(r -> r.getRangeNames(nameResolver).stream())
        .forEach(ranges::add);

    // Remove duplicates to avoid treating single-range properties as multi-range
    return ranges.stream().distinct().toList();
  }

  /**
   * Extracts the example value for a data property from annotations.
   *
   * <p>Looks for skos:example annotations in two places (in order):
   * <ol>
   *   <li>On the SubClassOf axiom containing the property restriction</li>
   *   <li>On the data property itself (as a default)</li>
   * </ol>
   *
   * @param dataProperty the data property to find an example for
   * @param subClassAxioms axioms that may contain restriction-level annotations
   * @return the example value string, or null if none found
   */
  private String extractExampleValue(OWLDataProperty dataProperty, List<OWLSubClassOfAxiom> subClassAxioms) {
    // First, look for a skos:example annotation on the restriction axiom itself
    return subClassAxioms.stream()
        .filter(axiom ->
            axiom.getSuperClass() instanceof OWLDataRestriction restriction
                && restriction.getProperty().asOWLDataProperty().getIRI().equals(dataProperty.getIRI()))
        .map(axiom -> axiom.getAnnotations().stream()
            .filter(annotation -> annotation.getProperty().getIRI().equals(OntologyConstants.SKOS_EXAMPLE))
            .findFirst()
            .flatMap(annotation -> annotation.mapLiteral(OWLLiteral::getLiteral)))
        .flatMap(Optional::stream)
        .findFirst()
        // Fall back to the annotation on the data property itself
        .orElse(OntologyUtil.defaultAnnotationsOf(dataProperty, context.getOntology())
            .getOrDefault(OntologyConstants.SKOS_EXAMPLE.getShortForm(), null));
  }

  /**
   * Processes all data properties and adds them to the schema.
   *
   * <p>For each data property discovered by the SchemaVisitor:
   * <ol>
   *   <li>Looks up the OWLDataProperty in the ontology</li>
   *   <li>Extracts description, label, example, ranges, and enum values</li>
   *   <li>Creates a DataPropertyMapper to generate the schema</li>
   *   <li>Adds the property to the resource schema</li>
   *   <li>Marks as required if restrictions indicate requiredness</li>
   * </ol>
   *
   * @param schema the resource schema to add properties to
   * @param visitor visitor containing collected property information
   * @param restrictions restrictions map
   * @param subClassAxioms axioms for extracting example annotations
   */
  private void processDataProperties(
      Schema<?> schema,
      SchemaVisitor visitor,
      Map<String, Set<RestrictionInfo>> restrictions,
      List<OWLSubClassOfAxiom> subClassAxioms) {

    Multimap<String, OWLDatatype> dataPropertyRanges = visitor.getDataPropertyRanges();
    Set<String> dataPropertyNames = visitor.getDataPropertyNames();

    for (String propertyName : dataPropertyNames) {
      Optional<OWLDataProperty> dataPropertyOpt = findDataProperty(propertyName);
      if (dataPropertyOpt.isEmpty()) {
        continue;
      }

      OWLDataProperty dataProperty = dataPropertyOpt.get();
      Set<RestrictionInfo> propertyRestrictions = restrictions.getOrDefault(propertyName, Set.of());

      String propertyDescription = OntologyUtil.getDescription(dataProperty, context.getOntology());
      String label = getLabel(dataProperty);
      String exampleValue = extractExampleValue(dataProperty, subClassAxioms);
      List<String> rangeTypes = extractPropertyRanges(propertyName, dataPropertyRanges, restrictions);
      List<String> enumValues = propertyRestrictions.stream()
          .flatMap(r -> r.getEnumValues().stream())
          .toList();

      DataPropertyMapper mapper = new DataPropertyMapper(
          context.getConfig(),
          nameResolver.resolve(dataProperty),
          label,
          propertyDescription,
          exampleValue,
          propertyRestrictions,
          enumValues,
          rangeTypes);

      try {
        schema.addProperty(mapper.getName(), mapper.getSchemaByDataProperty());
        if (mapper.isRequired()) {
          schema.addRequiredItem(mapper.getName());
        }
      } catch (Exception e) {
        throw new RuntimeException("Error when processing data property " + mapper.getName(), e);
      }
    }
  }

  /**
   * Processes all object properties and adds them to the schema.
   *
   * <p>For each object property discovered by the SchemaVisitor:
   * <ol>
   *   <li>Looks up the OWLObjectProperty in the ontology</li>
   *   <li>Extracts description, label, and range classes</li>
   *   <li>Creates an ObjectPropertyMapper to generate the schema</li>
   *   <li>Adds the property to the resource schema</li>
   *   <li>Marks as required if restrictions indicate requiredness</li>
   * </ol>
   *
   * @param schema the resource schema to add properties to
   * @param visitor visitor containing collected property information
   * @param restrictions restrictions map
   */
  private void processObjectProperties(
      Schema<?> schema,
      SchemaVisitor visitor,
      Map<String, Set<RestrictionInfo>> restrictions) {

    Multimap<String, OWLClass> objectPropertyRanges = visitor.getObjectPropertyRanges();
    Set<String> objectPropertyNames = visitor.getObjectPropertyNames();

    for (String propertyName : objectPropertyNames) {
      Optional<OWLObjectProperty> objectPropertyOpt = findObjectProperty(propertyName);
      if (objectPropertyOpt.isEmpty()) {
        continue;
      }

      OWLObjectProperty objectProperty = objectPropertyOpt.get();
      Set<RestrictionInfo> propertyRestrictions = restrictions.getOrDefault(propertyName, Set.of());

      String propertyDescription = OntologyUtil.getDescription(objectProperty, context.getOntology());
      String propertyLabel = getLabel(objectProperty);
      List<String> rangeClasses = extractPropertyRanges(propertyName, objectPropertyRanges, restrictions);

      ObjectPropertyMapper mapper = new ObjectPropertyMapper(
          context, propertyName, propertyLabel, propertyDescription, propertyRestrictions, rangeClasses);

      schema.addProperty(mapper.getName(), mapper.getSchema());
      if (mapper.isRequired()) {
        schema.addRequiredItem(mapper.getName());
      }
    }
  }

  /**
   * Processes taxonomy axioms and adds enum properties to the schema.
   *
   * <p>This method first checks for taxonomy patterns detected by SchemaVisitor
   * (patterns A, B, C, D) and uses TaxonomyPatternMapper for those. Falls back
   * to existing logic for class-based taxonomies that weren't detected as patterns.
   *
   * <p>Supported patterns:
   * <ul>
   *   <li><b>Pattern A</b>: Inline enum with untyped individuals (owl:oneOf)</li>
   *   <li><b>Pattern B</b>: Typed individuals with metadata (owl:oneOf)</li>
   *   <li><b>Pattern C</b>: Class-based taxonomy (extensible)</li>
   *   <li><b>Pattern D</b>: SKOS taxonomy (FHIR-compatible)</li>
   *   <li><b>Legacy</b>: Direct individual references or class-based lookup</li>
   * </ul>
   *
   * @param schema the resource schema to add taxonomy properties to
   * @param taxonomyAxioms axioms identified as taxonomy definitions
   * @param visitor the schema visitor containing detected taxonomy patterns
   * @param restrictions restrictions map
   */
  private void processTaxonomyProperties(
      Schema<?> schema,
      List<OWLSubClassOfAxiom> taxonomyAxioms,
      SchemaVisitor visitor,
      Map<String, Set<RestrictionInfo>> restrictions) {

    // First, process detected taxonomy patterns from SchemaVisitor
    Set<String> processedProperties = new HashSet<>();
    Map<String, TaxonomyInfo> taxonomyPatterns = visitor.getTaxonomyPatterns();

    for (Map.Entry<String, TaxonomyInfo> entry : taxonomyPatterns.entrySet()) {
      String propertyName = entry.getKey();
      TaxonomyInfo info = entry.getValue();

      if (info.pattern() == TaxonomyPattern.NONE) {
        continue;
      }

      Set<RestrictionInfo> propertyRestrictions = restrictions.getOrDefault(propertyName, Set.of());
      Optional<OWLObjectProperty> objectPropertyOpt = findObjectProperty(propertyName);

      String description = objectPropertyOpt
          .map(prop -> OntologyUtil.getDescription(prop, context.getOntology()))
          .orElse("");
      String label = objectPropertyOpt
          .map(this::getLabel)
          .orElse(propertyName);

      TaxonomyPatternMapper mapper = new TaxonomyPatternMapper(
          context, info, propertyRestrictions, description, label);

      schema.addProperty(mapper.getName(), mapper.getSchema());
      if (mapper.isRequired()) {
        schema.addRequiredItem(mapper.getName());
      }

      processedProperties.add(propertyName);
    }

    // Fall back to legacy processing for taxonomy axioms not covered by pattern detection
    Set<OWLObjectProperty> taxonomyPropertyNames = taxonomyAxioms.stream()
        .map(OWLSubClassOfAxiom::getSuperClass)
        .flatMap(superCls -> superCls.getObjectPropertiesInSignature().stream())
        .filter(prop -> !processedProperties.contains(nameResolver.resolve(prop)))
        .collect(Collectors.toSet());

    for (OWLObjectProperty taxonomyProperty : taxonomyPropertyNames) {
      for (OWLSubClassOfAxiom axiom : taxonomyAxioms) {
        OWLClassExpression superCls = axiom.getSuperClass();

        for (OWLObjectProperty objectProperty : superCls.getObjectPropertiesInSignature()) {
          if (!objectProperty.equals(taxonomyProperty)) {
            continue;
          }

          Set<RestrictionInfo> taxonomyRestrictions = new LinkedHashSet<>();
          RestrictionInfo.from(superCls).ifPresent(taxonomyRestrictions::add);

          // Taxonomy detection: check if axiom references named individuals directly
          Set<OWLNamedIndividual> individualsInSignature = superCls.getIndividualsInSignature();

          if (!individualsInSignature.isEmpty()) {
            // Direct individual reference - use individual labels as enum values
            addTaxonomyPropertyToSchema(schema,
                nameResolver.resolve(taxonomyProperty),
                OntologyUtil.getDescription(cls, context.getOntology()),
                getLabel(taxonomyProperty),
                individualsInSignature.stream().map(this::getLabel).toList(),
                taxonomyRestrictions);
          } else {
            // Indirect reference via class - look up individuals belonging to the class
            for (OWLClass taxonomyClass : superCls.getClassesInSignature()) {
              List<OWLNamedIndividual> individuals = EntitySearcher
                  .getIndividuals(taxonomyClass, context.getOntology())
                  .flatMap(Narrow.to(OWLNamedIndividual.class))
                  .toList();

              addTaxonomyPropertyToSchema(schema,
                  taxonomyName(nameResolver.resolve(taxonomyClass)),
                  OntologyUtil.getDescription(taxonomyClass, context.getOntology()),
                  getLabel(taxonomyClass),
                  individuals.stream().map(this::getLabel).toList(),
                  taxonomyRestrictions);
            }
          }
        }
      }
    }
  }


  /**
   * Adds a taxonomy property to the schema.
   *
   * @param schema the schema to add the property to
   * @param name the property name
   * @param description the property description
   * @param label the property label
   * @param enumValues the list of allowed enum values
   * @param restrictions the restrictions for this property
   */
  private void addTaxonomyPropertyToSchema(
      Schema<?> schema,
      String name,
      String description,
      String label,
      List<String> enumValues,
      Set<RestrictionInfo> restrictions) {
    TaxonomyPropertyMapper mapper = new TaxonomyPropertyMapper(
        context, name, description, label, enumValues, restrictions);
    schema.addProperty(mapper.getName(), mapper.getTaxonomySchemaObject());
    if (mapper.isRequired()) {
      schema.addRequiredItem(mapper.getName());
    }
  }

  /**
   * Logs a warning when no properties were found for a class.
   *
   * <p>This typically indicates that the ontology is missing apiLabel annotations
   * on the property restrictions, or that the schema label doesn't match.
   *
   * @param analyzedClass the class that had no mappable properties
   * @param axioms all collected axioms (for diagnostic output)
   */
  private void logMissingPropertiesWarning(OWLClass analyzedClass, AxiomCollection axioms) {
    logger.warning("No properties with " + OntologyConstants.apiLabel
        + " annotation found for: " + analyzedClass);

    List<OWLSubClassOfAxiom> allAxioms = Stream.of(axioms.superClass(), axioms.subClass(), axioms.taxonomy())
        .flatMap(Collection::stream)
        .toList();

    if (!allAxioms.isEmpty()) {
      allAxioms.stream()
          .map(axiom -> axiom.getSuperClass().toString())
          .forEach(s -> logger.warning("\tPossible property: " + s));
    }
  }

  private List<OWLSubClassOfAxiom> getTaxonomyAxioms(OWLClass analyzedClass) {
    Set<OWLSubClassOfAxiom> subAx = context.getOntology().getSubClassAxiomsForSubClass(analyzedClass);
    String schemaAnnotation = getSchemaAnnotation(context.getSchemaLabel());

    return subAx.stream().filter(ax -> ax.annotations()
        .anyMatch(annotation -> annotation.getValue().toString().equals(schemaAnnotation))).filter(ax -> {
      OWLClassExpression superCls = ax.getSuperClass();
      return !superCls.getObjectPropertiesInSignature().isEmpty() && (superCls.individualsInSignature()
          .anyMatch(individual -> !EntitySearcher.getObjectPropertyValues(individual, context.getOntology())
              .isEmpty()) || superCls.classesInSignature()
          .anyMatch(cls -> EntitySearcher.getIndividuals(cls, context.getOntology()).findAny().isPresent()));
    }).collect(Collectors.toList());
  }

  public String getSchemaName() {
    return nameResolver.resolve(cls);
  }

  private String getSchemaAnnotation(String schema) {
    return '"' + schema + '"' + "^^xsd:string";
  }

  private String taxonomyName(String taxonomy_name) {
    if (StringUtils.countMatches(taxonomy_name, "_") > 0) {
      return taxonomy_name.substring(taxonomy_name.lastIndexOf("_") + 1);
    }
    return taxonomy_name.substring(0, 1).toUpperCase() + taxonomy_name.substring(1);
  }

  private String getLabel(final OWLEntity entity) {
    return OntologyUtil.getTitle(entity, context.getOntology());
  }

  private Stream<OWLSubClassOfAxiom> getSuperClassAxioms(OWLClass analyzedClass,
                                                         @Nullable Set<OWLClass> ignoreClasses) {
    final Set<OWLClass> processedClasses = Optional.ofNullable(ignoreClasses).orElse(new HashSet<OWLClass>());
    final String schemaAnnotation = getSchemaAnnotation(context.getSchemaLabel());
    return context.getOntology().subClassAxiomsForSubClass(analyzedClass)
        .filter(WithAnnotation.of(OntologyConstants.apiLabel, context.getSchemaLabel()))
        .map(OWLSubClassOfAxiom::getSuperClass).filter(OWLClassExpression::isOWLClass).map(AsOWLClass::asOWLClass)
        .filter(Predicate.not(processedClasses::contains)).peek(processedClasses::add) // side effect
        .flatMap(context.getOntology()::subClassAxiomsForSubClass).flatMap(owlSubClassOfAxiom -> {
          final OWLClassExpression superClass = owlSubClassOfAxiom.getSuperClass();
          final List<OWLSubClassOfAxiom> superClassAxioms = new ArrayList<>();
          if (superClass.isOWLClass()) {
            getSuperClassAxioms(superClass.asOWLClass(), processedClasses).forEach(superClassAxioms::add);
          }
          if (owlSubClassOfAxiom.annotations()
              .anyMatch(owlAnnotation -> owlAnnotation.getValue().toString().equals(schemaAnnotation))) {
            superClassAxioms.add(owlSubClassOfAxiom);
          }
          return superClassAxioms.stream();
        });
  }

}

