package com.grl.component.mapper;

import com.grl.component.asg.OntologyConstants;
import com.grl.component.asg.OpenApiConstants;
import com.grl.component.asg.configuration.YamlConfig;
import com.grl.component.owl.Narrow;
import com.grl.component.owl.OntologyUtil;
import com.grl.component.owl.WithIRI;
import com.grl.component.schema.PropertyNameResolver;
import com.grl.component.schema.RestrictionInfo;
import io.swagger.v3.oas.models.media.ArraySchema;
import io.swagger.v3.oas.models.media.ComposedSchema;
import io.swagger.v3.oas.models.media.ObjectSchema;
import io.swagger.v3.oas.models.media.Schema;
import io.swagger.v3.oas.models.media.StringSchema;
import java.util.HashMap;
import java.util.List;
import java.util.Map;
import java.util.Optional;
import java.util.Set;
import org.apache.commons.collections.CollectionUtils;
import org.semanticweb.owlapi.model.HasProperty;
import org.semanticweb.owlapi.model.IRI;
import org.semanticweb.owlapi.model.OWLClass;
import org.semanticweb.owlapi.model.OWLOntology;
import org.semanticweb.owlapi.search.EntitySearcher;

public class ObjectPropertyMapper {

  private final PropertyNameResolver nameResolver = new PropertyNameResolver();
  private final String name;
  private final String label;
  private final String description;
  private final List<String> ref;
  private final boolean array;

  public boolean isRequired() {
    return isRequired;
  }

  private final boolean isRequired;
  private final Set<RestrictionInfo> restrictions;
  private final MappingContext context;

  public ObjectPropertyMapper(MappingContext context, String name, String label, String description,
      Set<RestrictionInfo> restrictions, List<String> ref) {
    this.name = name;
    this.label = label;
    this.description = description;
    this.ref = ref;
    this.restrictions = restrictions;
    this.context = context;

    // Compute array and required from restrictions
    YamlConfig config = context.getConfig();
    this.array =
        restrictions != null && restrictions.stream().anyMatch(RestrictionInfo::impliesArray);
    this.isRequired = config.isEnforceRequiredness() &&
        restrictions != null && restrictions.stream().anyMatch(RestrictionInfo::impliesRequired);
  }

  public Schema getSchema() {
    Schema result;
    if (this.ref.isEmpty()) {
      result = getComposedSchemaObject(this.ref, this.array);
    } else if (this.ref.size() > 1) {
      result = getComposedSchemaObject(this.ref, this.array);
    } else {
      result = getObjectPropertiesByRef(this.ref.getFirst(), this.array);
    }
    result.setTitle(label);
    return result;
  }

  private Schema getObjectPropertiesByRef(String ref, boolean isArray) {
    // create schema for referenced class
    context.addSchema(ref);
    Optional<Schema> referenceSchema = mapLinkedResourceClass(context.getManager().getOWLDataFactory()
        .getOWLClass(IRI.create(context.getDefaultOntologyPrefixIRI(), ref)));
    if (isArray) {
      // For array of references create array schema and set items to a list of references to an object
      ArraySchema array = new ArraySchema();
      // NEW: Use typed restrictions (Phase 4)
      for (RestrictionInfo restriction : this.restrictions) {
        restriction.applyToArraySchema(array);
      }
      Schema itemSchema = referenceSchema.orElseGet(() -> new ComposedSchema().$ref(ref));
      array.items(itemSchema);
      return array;
    } else {
      // For a single item reference, use allOf: [ referenceschema ]
      Schema<?> allOfItems = new ArraySchema().type(null)
          .items(referenceSchema.orElseGet(() -> new ComposedSchema().$ref(ref)));
      // NOTE: someValuesFrom/allValuesFrom don't require special handling for non-array refs
      // HasValue restrictions would need special handling if encountered
      if (CollectionUtils.isNotEmpty(allOfItems.getAllOf())) {
        if (allOfItems.getAllOf().size() > 1) {
          return new ComposedSchema().allOf(List.of(allOfItems));
        } else {
          return allOfItems.getAllOf().getFirst();
        }
      } else {
        return allOfItems.getItems();
      }
    }
  }

  private Schema getComposedSchemaObject(List<String> refs, boolean isArray) {
    ObjectSchema rangeObjectSchema = new ObjectSchema();
    Map<String, Schema> rangeProperties = new HashMap<>();

    // Create a schema reference for each of the given references
    for (String ref : refs) {
      // create schema for referenced class
      context.addSchema(ref);
      OWLClass rangeCls = context.getManager().getOWLDataFactory()
          .getOWLClass(IRI.create(context.getDefaultOntologyPrefixIRI() + ref));
      String rangeDescription = OntologyUtil.getDescription(rangeCls, context.getOntology());
      Schema<?> rangePropertiesSchema = mapLinkedResourceClass(rangeCls).orElseGet(() -> {
        ResourceSchemaMapper rangeSchema = new ResourceSchemaMapper(context, rangeCls, rangeDescription);
        Schema childSchema = new ComposedSchema();
        childSchema.setName(rangeSchema.getSchemaName());
        childSchema.setDescription(rangeDescription);
        childSchema.set$ref(ref);
        return childSchema;
      });
      rangePropertiesSchema.setTitle(OntologyUtil.getTitle(rangeCls, context.getOntology()));
      rangeProperties.put(ref, rangePropertiesSchema);
    }
    rangeObjectSchema.setAdditionalProperties(false);
    rangeObjectSchema.setProperties(rangeProperties);

    if (!isArray) {
      // Is singular
      return rangeObjectSchema;
    } else {
      ArraySchema arraySchema = new ArraySchema();
      arraySchema.setType("array");
      arraySchema.setDescription(this.description);
      arraySchema.setItems(rangeObjectSchema);
      arraySchema.setType("array");
      // NEW: Use typed restrictions (Phase 4)
      for (RestrictionInfo restriction : this.restrictions) {
        restriction.applyToArraySchema(arraySchema);
      }
      return arraySchema;
    }
  }

  public String getName() {
    return name;
  }

  /**
   * Check whether given class is a fully addressable item in our model - if so will have its own identifier field
   * and be exposed
   * as an api resource.
   * The returned schema contains an extension field x-grl-model-link with the string value of the API model name the
   * id refers too
   *
   * @param cls class to check
   * @return schema for identifier if a fully addressable model item (i.e. has an id field etc)
   * @throws RuntimeException if the determined identifier class does not have a single uniqueText data property
   */
  private Optional<Schema> mapLinkedResourceClass(OWLClass cls) {
    if (context.getResourceClasses().contains(cls)) {
      final OWLOntology ontology = context.getOntology();
      return EntitySearcher.getSuperClasses(cls, ontology).flatMap(Narrow.to(HasProperty.class))
          .filter(WithIRI.onPropertyOf(OntologyConstants.apiID)).findFirst()
          .map(identifierClass -> {
            // Check ontology of id class found
            return new StringSchema().extensions(
                    Map.of(OpenApiConstants.X_GRL_MODEL_LINK, nameResolver.resolve(cls)))
                .description("Unique identifier of " + nameResolver.resolve(cls))
                .example(nameResolver.resolve(cls) + "-12345");

          });
    } else
      return Optional.empty();
  }
}

