package com.grl.component.owl;

import com.grl.component.schema.PropertyNameResolver;
import java.util.Objects;
import java.util.function.Predicate;
import org.semanticweb.owlapi.model.HasIRI;
import org.semanticweb.owlapi.model.HasProperty;
import org.semanticweb.owlapi.model.IRI;
import org.semanticweb.owlapi.model.OWLClassExpression;

/**
 * Predicate for matching uris on ontology entities, short and logform versions of each
 */
public class WithIRI implements Predicate<HasIRI> {

  private static final PropertyNameResolver nameResolver = new PropertyNameResolver();
  private final boolean asShortForm;
  private final IRI iri;

  private WithIRI(String shortIRI) {
    this.iri = Objects.requireNonNull(IRI.create("", shortIRI));
    asShortForm = true;
  }

  private WithIRI(IRI iri) {
    this.iri = Objects.requireNonNull(iri);
    asShortForm = false;
  }

  @Override
  public boolean test(HasIRI hasIRI) {
    if (hasIRI != null) {
      return asShortForm ? nameResolver.resolve(hasIRI).equals(nameResolver.resolve(iri))
          : hasIRI.getIRI().equals(iri);
    } else
      return false;
  }

  public static Predicate<HasIRI> of(final String shortForm) {
    return new WithIRI(shortForm);
  }

  public static Predicate<HasIRI> of(final IRI iri) {
    return new WithIRI(nameResolver.resolve(iri));
  }

  public static Predicate<HasProperty> onPropertyOf(final String shortForm) {
    return new Predicate<>() {
      private final WithIRI withIRI = new WithIRI(shortForm);

      @Override
      public boolean test(HasProperty hasProperty) {
        return hasProperty != null && hasProperty.getProperty() instanceof HasIRI hasIRI && withIRI.test(hasIRI);
      }
    };
  }

  public static Predicate<HasProperty> onPropertyOf(final IRI iri) {
    return new Predicate<>() {
      private final WithIRI withIRI = new WithIRI(iri);

      @Override
      public boolean test(HasProperty hasProperty) {
        return hasProperty != null && hasProperty.getProperty() instanceof HasIRI hasIRI && withIRI.test(hasIRI);
      }
    };
  }

  public static <T extends OWLClassExpression> Predicate<T> onClassExpressionTypeOf(
      final String shortForm) {
    return new Predicate<>() {
      private final WithIRI withIRI = new WithIRI(shortForm);

      @Override
      public boolean test(T expression) {
        return expression.getClassExpressionType() instanceof HasIRI hasIRI && withIRI.test(hasIRI);
      }
    };
  }

  public static <T extends OWLClassExpression> Predicate<T> onClassExpressionTypeOf(final IRI iri) {
    return new Predicate<>() {
      private final WithIRI withIRI = new WithIRI(iri);

      @Override
      public boolean test(T expression) {
        return expression.getClassExpressionType() instanceof HasIRI hasIRI && withIRI.test(hasIRI);
      }
    };
  }

}

