   247→
   248→  /**
   249→   * Finds a data property in the ontology by its resolved name.
   250→   *
   251→   * @param propertyName the short-form property name (e.g., "firstName")
   252→   * @return the matching OWLDataProperty, or empty if not found
   253→   */
   254→  private Optional<OWLDataProperty> findDataProperty(String propertyName) {
   255→    return context.getOntology()
   256→        .getDataPropertiesInSignature().stream()
   257→        .filter(prop -> nameResolver.resolve(prop).equals(propertyName))
   258→        .findFirst();
   259→  }
   260→
   261→  /**
   262→   * Finds an object property in the ontology by its resolved name.
   263→   *
   264→   * @param propertyName the short-form property name (e.g., "hasAddress")
   265→   * @return the matching OWLObjectProperty, or empty if not found
   266→   */
   267→  private Optional<OWLObjectProperty> findObjectProperty(String propertyName) {
   268→    return context.getOntology()
   269→        .getObjectPropertiesInSignature().stream()
   270→        .filter(prop -> nameResolver.resolve(prop).equals(propertyName))
   271→        .findFirst();
   272→  }
   273→
   274→  /**
   275→   * Extracts range type/class names for a property from multiple sources.
   276→   *
   277→   * <p>Ranges are collected from:
   278→   * <ol>
   279→   *   <li>The SchemaVisitor's property range multimap (from restriction fillers)</li>
   280→   *   <li>The RestrictionInfo objects themselves (via getRangeNames)</li>
   281→   * </ol>
   282→   *
   283→   * @param propertyName the property to extract ranges for
   284→   * @param rangesFromVisitor multimap of property → range classes/datatypes from visitor
   285→   * @param restrictions map of property → RestrictionInfo set
   286→   * @return deduplicated list of range type names
   287→   */
   288→  private List<String> extractPropertyRanges(
   289→      String propertyName,
   290→      Multimap<String, ? extends OWLEntity> rangesFromVisitor,
   291→      Map<String, Set<RestrictionInfo>> restrictions) {
   292→    List<String> ranges = new ArrayList<>();
   293→
   294→    // Extract from visitor's range multimap
   295→    rangesFromVisitor.get(propertyName).stream()
   296→        .map(nameResolver::resolve)
   297→        .forEach(ranges::add);
   298→
   299→    // Also extract from restrictions themselves
   300→    Set<RestrictionInfo> propertyRestrictions = restrictions.getOrDefault(propertyName, Set.of());
   301→    propertyRestrictions.stream()
   302→        .flatMap(r -> r.getRangeNames(nameResolver).stream())
   303→        .forEach(ranges::add);
   304→
   305→    // Remove duplicates to avoid treating single-range properties as multi-range
   306→    return ranges.stream().distinct().toList();
   307→  }
   308→
   309→  /**
   310→   * Extracts the example value for a data property from annotations.
   311→   *
   312→   * <p>Looks for skos:example annotations in two places (in order):
   313→   * <ol>
   314→   *   <li>On the SubClassOf axiom containing the property restriction</li>
   315→   *   <li>On the data property itself (as a default)</li>
   316→   * </ol>
   317→   *
   318→   * @param dataProperty the data property to find an example for
   319→   * @param subClassAxioms axioms that may contain restriction-level annotations
   320→   * @return the example value string, or null if none found
   321→   */
   322→  private String extractExampleValue(OWLDataProperty dataProperty, List<OWLSubClassOfAxiom> subClassAxioms) {
   323→    // First, look for a skos:example annotation on the restriction axiom itself
   324→    return subClassAxioms.stream()
   325→        .filter(axiom ->
   326→            axiom.getSuperClass() instanceof OWLDataRestriction restriction
   327→                && restriction.getProperty().asOWLDataProperty().getIRI().equals(dataProperty.getIRI()))
   328→        .map(axiom -> axiom.getAnnotations().stream()
   329→            .filter(annotation -> annotation.getProperty().getIRI().equals(OntologyConstants.SKOS_EXAMPLE))
   330→            .findFirst()
   331→            .flatMap(annotation -> annotation.mapLiteral(OWLLiteral::getLiteral)))
   332→        .flatMap(Optional::stream)
   333→        .findFirst()
   334→        // Fall back to the annotation on the data property itself
   335→        .orElse(OntologyUtil.defaultAnnotationsOf(dataProperty, context.getOntology())
   336→            .getOrDefault(OntologyConstants.SKOS_EXAMPLE.getShortForm(), null));
   337→  }
   338→
   339→  /**
   340→   * Processes all data properties and adds them to the schema.
   341→   *
   342→   * <p>For each data property discovered by the SchemaVisitor:
   343→   * <ol>
   344→   *   <li>Looks up the OWLDataProperty in the ontology</li>
   345→   *   <li>Extracts description, label, example, ranges, and enum values</li>
   346→   *   <li>Creates a DataPropertyMapper to generate the schema</li>
   347→   *   <li>Adds the property to the resource schema</li>
   348→   *   <li>Marks as required if restrictions indicate requiredness</li>
   349→   * </ol>
   350→   *
   351→   * @param schema the resource schema to add properties to
   352→   * @param visitor visitor containing collected property information
   353→   * @param restrictions restrictions map
   354→   * @param subClassAxioms axioms for extracting example annotations
   355→   */
   356→  private void processDataProperties(
   357→      Schema<?> schema,
   358→      SchemaVisitor visitor,
   359→      Map<String, Set<RestrictionInfo>> restrictions,
   360→      List<OWLSubClassOfAxiom> subClassAxioms) {
   361→
   362→    Multimap<String, OWLDatatype> dataPropertyRanges = visitor.getDataPropertyRanges();
   363→    Set<String> dataPropertyNames = visitor.getDataPropertyNames();
   364→
   365→    for (String propertyName : dataPropertyNames) {
   366→      Optional<OWLDataProperty> dataPropertyOpt = findDataProperty(propertyName);
   367→      if (dataPropertyOpt.isEmpty()) {
   368→        continue;
   369→      }
   370→
   371→      OWLDataProperty dataProperty = dataPropertyOpt.get();
   372→      Set<RestrictionInfo> propertyRestrictions = restrictions.getOrDefault(propertyName, Set.of());
   373→
   374→      String propertyDescription = OntologyUtil.getDescription(dataProperty, context.getOntology());
   375→      String label = getLabel(dataProperty);
   376→      String exampleValue = extractExampleValue(dataProperty, subClassAxioms);
   377→      List<String> rangeTypes = extractPropertyRanges(propertyName, dataPropertyRanges, restrictions);
   378→      List<String> enumValues = propertyRestrictions.stream()
   379→          .flatMap(r -> r.getEnumValues().stream())
   380→          .toList();
   381→
   382→      DataPropertyMapper mapper = new DataPropertyMapper(
   383→          context.getConfig(),
   384→          nameResolver.resolve(dataProperty),
   385→          label,
   386→          propertyDescription,
   387→          exampleValue,
   388→          propertyRestrictions,
   389→          enumValues,
   390→          rangeTypes);
   391→
   392→      try {
   393→        schema.addProperty(mapper.getName(), mapper.getSchemaByDataProperty());
   394→        if (mapper.isRequired()) {
   395→          schema.addRequiredItem(mapper.getName());
   396→        }
   397→      } catch (Exception e) {
   398→        throw new RuntimeException("Error when processing data property " + mapper.getName(), e);
   399→      }
   400→    }
   401→  }
   402→
   403→  /**
   404→   * Processes all object properties and adds them to the schema.
   405→   *
   406→   * <p>For each object property discovered by the SchemaVisitor:
   407→   * <ol>
   408→   *   <li>Looks up the OWLObjectProperty in the ontology</li>
   409→   *   <li>Extracts description, label, and range classes</li>
   410→   *   <li>Creates an ObjectPropertyMapper to generate the schema</li>
   411→   *   <li>Adds the property to the resource schema</li>
   412→   *   <li>Marks as required if restrictions indicate requiredness</li>
   413→   * </ol>
   414→   *
   415→   * @param schema the resource schema to add properties to
   416→   * @param visitor visitor containing collected property information
   417→   * @param restrictions restrictions map
   418→   */
   419→  private void processObjectProperties(
   420→      Schema<?> schema,
   421→      SchemaVisitor visitor,
   422→      Map<String, Set<RestrictionInfo>> restrictions) {
   423→
   424→    Multimap<String, OWLClass> objectPropertyRanges = visitor.getObjectPropertyRanges();
   425→    Set<String> objectPropertyNames = visitor.getObjectPropertyNames();
   426→
   427→    for (String propertyName : objectPropertyNames) {
   428→      Optional<OWLObjectProperty> objectPropertyOpt = findObjectProperty(propertyName);
   429→      if (objectPropertyOpt.isEmpty()) {
   430→        continue;
   431→      }
   432→
   433→      OWLObjectProperty objectProperty = objectPropertyOpt.get();
   434→      Set<RestrictionInfo> propertyRestrictions = restrictions.getOrDefault(propertyName, Set.of());
   435→
   436→      String propertyDescription = OntologyUtil.getDescription(objectProperty, context.getOntology());
   437→      String propertyLabel = getLabel(objectProperty);
   438→      List<String> rangeClasses = extractPropertyRanges(propertyName, objectPropertyRanges, restrictions);
   439→
   440→      ObjectPropertyMapper mapper = new ObjectPropertyMapper(
   441→          context, propertyName, propertyLabel, propertyDescription, propertyRestrictions, rangeClasses);
   442→
   443→      schema.addProperty(mapper.getName(), mapper.getSchema());
   444→      if (mapper.isRequired()) {
   445→        schema.addRequiredItem(mapper.getName());
   446→      }
   447→    }
   448→  }
   449→
   450→  /**
   451→   * Processes taxonomy axioms and adds enum properties to the schema.
   452→   *
   453→   * <p>This method first checks for taxonomy patterns detected by SchemaVisitor
   454→   * (patterns A, B, C, D) and uses TaxonomyPatternMapper for those. Falls back
   455→   * to existing logic for class-based taxonomies that weren't detected as patterns.
   456→   *
   457→   * <p>Supported patterns:
   458→   * <ul>
   459→   *   <li><b>Pattern A</b>: Inline enum with untyped individuals (owl:oneOf)</li>
   460→   *   <li><b>Pattern B</b>: Typed individuals with metadata (owl:oneOf)</li>
   461→   *   <li><b>Pattern C</b>: Class-based taxonomy (extensible)</li>
   462→   *   <li><b>Pattern D</b>: SKOS taxonomy (FHIR-compatible)</li>
   463→   *   <li><b>Legacy</b>: Direct individual references or class-based lookup</li>
   464→   * </ul>
   465→   *
   466→   * @param schema the resource schema to add taxonomy properties to
   467→   * @param taxonomyAxioms axioms identified as taxonomy definitions
   468→   * @param visitor the schema visitor containing detected taxonomy patterns
   469→   * @param restrictions restrictions map
   470→   */
   471→  private void processTaxonomyProperties(
   472→      Schema<?> schema,
   473→      List<OWLSubClassOfAxiom> taxonomyAxioms,
   474→      SchemaVisitor visitor,
   475→      Map<String, Set<RestrictionInfo>> restrictions) {
   476→
   477→    // First, process detected taxonomy patterns from SchemaVisitor
   478→    Set<String> processedProperties = new HashSet<>();
   479→    Map<String, TaxonomyInfo> taxonomyPatterns = visitor.getTaxonomyPatterns();
   480→
   481→    for (Map.Entry<String, TaxonomyInfo> entry : taxonomyPatterns.entrySet()) {
   482→      String propertyName = entry.getKey();
   483→      TaxonomyInfo info = entry.getValue();
   484→
   485→      if (info.pattern() == TaxonomyPattern.NONE) {
   486→        continue;
   487→      }
   488→
   489→      Set<RestrictionInfo> propertyRestrictions = restrictions.getOrDefault(propertyName, Set.of());
   490→      Optional<OWLObjectProperty> objectPropertyOpt = findObjectProperty(propertyName);
   491→
   492→      String description = objectPropertyOpt
   493→          .map(prop -> OntologyUtil.getDescription(prop, context.getOntology()))
   494→          .orElse("");
   495→      String label = objectPropertyOpt
   496→          .map(this::getLabel)
   497→          .orElse(propertyName);
   498→
   499→      TaxonomyPatternMapper mapper = new TaxonomyPatternMapper(
   500→          context, info, propertyRestrictions, description, label);
   501→
   502→      schema.addProperty(mapper.getName(), mapper.getSchema());
   503→      if (mapper.isRequired()) {
   504→        schema.addRequiredItem(mapper.getName());
   505→      }
   506→
   507→      processedProperties.add(propertyName);
   508→    }
   509→
   510→    // Fall back to legacy processing for taxonomy axioms not covered by pattern detection
   511→    Set<OWLObjectProperty> taxonomyPropertyNames = taxonomyAxioms.stream()
   512→        .map(OWLSubClassOfAxiom::getSuperClass)
   513→        .flatMap(superCls -> superCls.getObjectPropertiesInSignature().stream())
   514→        .filter(prop -> !processedProperties.contains(nameResolver.resolve(prop)))
   515→        .collect(Collectors.toSet());
   516→
   517→    for (OWLObjectProperty taxonomyProperty : taxonomyPropertyNames) {
   518→      for (OWLSubClassOfAxiom axiom : taxonomyAxioms) {
   519→        OWLClassExpression superCls = axiom.getSuperClass();
   520→
   521→        for (OWLObjectProperty objectProperty : superCls.getObjectPropertiesInSignature()) {
   522→          if (!objectProperty.equals(taxonomyProperty)) {
   523→            continue;
   524→          }
   525→
   526→          Set<RestrictionInfo> taxonomyRestrictions = new LinkedHashSet<>();
   527→          RestrictionInfo.from(superCls).ifPresent(taxonomyRestrictions::add);
   528→
   529→          // Taxonomy detection: check if axiom references named individuals directly
   530→          Set<OWLNamedIndividual> individualsInSignature = superCls.getIndividualsInSignature();
   531→
   532→          if (!individualsInSignature.isEmpty()) {
   533→            // Direct individual reference - use individual labels as enum values
   534→            addTaxonomyPropertyToSchema(schema,
   535→                nameResolver.resolve(taxonomyProperty),
   536→                OntologyUtil.getDescription(cls, context.getOntology()),
   537→                getLabel(taxonomyProperty),
   538→                individualsInSignature.stream().map(this::getLabel).toList(),
   539→                taxonomyRestrictions);
   540→          } else {
   541→            // Indirect reference via class - look up individuals belonging to the class
   542→            for (OWLClass taxonomyClass : superCls.getClassesInSignature()) {
   543→              List<OWLNamedIndividual> individuals = EntitySearcher
   544→                  .getIndividuals(taxonomyClass, context.getOntology())
   545→                  .flatMap(Narrow.to(OWLNamedIndividual.class))
   546→                  .toList();
   547→
   548→              addTaxonomyPropertyToSchema(schema,
   549→                  taxonomyName(nameResolver.resolve(taxonomyClass)),
   550→                  OntologyUtil.getDescription(taxonomyClass, context.getOntology()),
   551→                  getLabel(taxonomyClass),
   552→                  individuals.stream().map(this::getLabel).toList(),
   553→                  taxonomyRestrictions);
   554→            }
   555→          }
   556→        }
   557→      }
   558→    }
   559→  }
   560→
   561→
   562→  /**
   563→   * Adds a taxonomy property to the schema.
   564→   *
   565→   * @param schema the schema to add the property to
   566→   * @param name the property name
   567→   * @param description the property description
   568→   * @param label the property label
   569→   * @param enumValues the list of allowed enum values
   570→   * @param restrictions the restrictions for this property
   571→   */
   572→  private void addTaxonomyPropertyToSchema(
   573→      Schema<?> schema,
   574→      String name,
   575→      String description,
   576→      String label,
   577→      List<String> enumValues,
   578→      Set<RestrictionInfo> restrictions) {
   579→    TaxonomyPropertyMapper mapper = new TaxonomyPropertyMapper(
   580→        context, name, description, label, enumValues, restrictions);
   581→    schema.addProperty(mapper.getName(), mapper.getTaxonomySchemaObject());
   582→    if (mapper.isRequired()) {
   583→      schema.addRequiredItem(mapper.getName());
   584→    }
   585→  }
   586→
   587→  /**
   588→   * Logs a warning when no properties were found for a class.
   589→   *
   590→   * <p>This typically indicates that the ontology is missing apiLabel annotations
   591→   * on the property restrictions, or that the schema label doesn't match.
   592→   *
   593→   * @param analyzedClass the class that had no mappable properties
   594→   * @param axioms all collected axioms (for diagnostic output)
   595→   */
   596→  private void logMissingPropertiesWarning(OWLClass analyzedClass, AxiomCollection axioms) {
   597→    logger.warning("No properties with " + OntologyConstants.apiLabel
   598→        + " annotation found for: " + analyzedClass);
   599→
   600→    List<OWLSubClassOfAxiom> allAxioms = Stream.of(axioms.superClass(), axioms.subClass(), axioms.taxonomy())
   601→        .flatMap(Collection::stream)
   602→        .toList();
   603→
   604→    if (!allAxioms.isEmpty()) {
   605→      allAxioms.stream()
   606→          .map(axiom -> axiom.getSuperClass().toString())
   607→          .forEach(s -> logger.warning("\tPossible property: " + s));
   608→    }
   609→  }
   610→
   611→  private List<OWLSubClassOfAxiom> getTaxonomyAxioms(OWLClass analyzedClass) {
   612→    Set<OWLSubClassOfAxiom> subAx = context.getOntology().getSubClassAxiomsForSubClass(analyzedClass);
   613→    String schemaAnnotation = getSchemaAnnotation(context.getSchemaLabel());
   614→
   615→    return subAx.stream().filter(ax -> ax.annotations()
   616→        .anyMatch(annotation -> annotation.getValue().toString().equals(schemaAnnotation))).filter(ax -> {
   617→      OWLClassExpression superCls = ax.getSuperClass();
   618→      return !superCls.getObjectPropertiesInSignature().isEmpty() && (superCls.individualsInSignature()
   619→          .anyMatch(individual -> !EntitySearcher.getObjectPropertyValues(individual, context.getOntology())
   620→              .isEmpty()) || superCls.classesInSignature()
   621→          .anyMatch(cls -> EntitySearcher.getIndividuals(cls, context.getOntology()).findAny().isPresent()));
   622→    }).collect(Collectors.toList());
   623→  }
   624→
   625→  public String getSchemaName() {
   626→    return nameResolver.resolve(cls);
   627→  }
   628→
   629→  private String getSchemaAnnotation(String schema) {
   630→    return '"' + schema + '"' + "^^xsd:string";
   631→  }
   632→
   633→  private String taxonomyName(String taxonomy_name) {
   634→    if (StringUtils.countMatches(taxonomy_name, "_") > 0) {
   635→      return taxonomy_name.substring(taxonomy_name.lastIndexOf("_") + 1);
   636→    }
   637→    return taxonomy_name.substring(0, 1).toUpperCase() + taxonomy_name.substring(1);
   638→  }
   639→
   640→  private String getLabel(final OWLEntity entity) {
   641→    return OntologyUtil.getTitle(entity, context.getOntology());
   642→  }
   643→
   644→  private Stream<OWLSubClassOfAxiom> getSuperClassAxioms(OWLClass analyzedClass,
   645→                                                         @Nullable Set<OWLClass> ignoreClasses) {
   646→    final Set<OWLClass> processedClasses = Optional.ofNullable(ignoreClasses).orElse(new HashSet<OWLClass>());
   647→    final String schemaAnnotation = getSchemaAnnotation(context.getSchemaLabel());
   648→    return context.getOntology().subClassAxiomsForSubClass(analyzedClass)
   649→        .filter(WithAnnotation.of(OntologyConstants.apiLabel, context.getSchemaLabel()))
   650→        .map(OWLSubClassOfAxiom::getSuperClass).filter(OWLClassExpression::isOWLClass).map(AsOWLClass::asOWLClass)
   651→        .filter(Predicate.not(processedClasses::contains)).peek(processedClasses::add) // side effect
   652→        .flatMap(context.getOntology()::subClassAxiomsForSubClass).flatMap(owlSubClassOfAxiom -> {
   653→          final OWLClassExpression superClass = owlSubClassOfAxiom.getSuperClass();
   654→          final List<OWLSubClassOfAxiom> superClassAxioms = new ArrayList<>();
   655→          if (superClass.isOWLClass()) {
   656→            getSuperClassAxioms(superClass.asOWLClass(), processedClasses).forEach(superClassAxioms::add);
   657→          }
   658→          if (owlSubClassOfAxiom.annotations()
   659→              .anyMatch(owlAnnotation -> owlAnnotation.getValue().toString().equals(schemaAnnotation))) {
   660→            superClassAxioms.add(owlSubClassOfAxiom);
   661→          }
   662→          return superClassAxioms.stream();
   663→        });
   664→  }
   665→
   666→}
