    14→/**
    15→ * Utility class for resolving property names from OWL properties. Provides consistent property name
    16→ * extraction using IRI short forms.
    17→ */
    18→public class PropertyNameResolver {
    19→
    20→  private final IRIShortFormProvider shortFormProvider;
    21→
    22→  public PropertyNameResolver() {
    23→    this(new SimpleIRIShortFormProvider());
    24→  }
    25→
    26→  public PropertyNameResolver(IRIShortFormProvider shortFormProvider) {
    27→    this.shortFormProvider = Objects.requireNonNull(shortFormProvider,
    28→        "shortFormProvider must not be null");
    29→  }
    30→
    31→  /**
    32→   * Resolves the short form name of an OWL object property.
    33→   *
    34→   * @param property the OWL object property
    35→   * @return the short form name, never null
    36→   * @throws NullPointerException if property is null
    37→   */
    38→  public String resolve(OWLObjectProperty property) {
    39→    Objects.requireNonNull(property, "property must not be null");
    40→    return resolve(property.getIRI());
    41→  }
    42→
    43→  /**
    44→   * Resolves the short form name of an OWL data property.
    45→   *
    46→   * @param property the OWL data property
    47→   * @return the short form name, never null
    48→   * @throws NullPointerException if property is null
    49→   */
    50→  public String resolve(OWLDataProperty property) {
    51→    Objects.requireNonNull(property, "property must not be null");
    52→    return resolve(property.getIRI());
    53→  }
    54→
    55→  /**
    56→   * Resolves the short form name of an OWL class.
    57→   *
    58→   * @param owlClass the OWL class
    59→   * @return the short form name, never null
    60→   * @throws NullPointerException if owlClass is null
    61→   */
    62→  public String resolve(OWLClass owlClass) {
    63→    Objects.requireNonNull(owlClass, "owlClass must not be null");
    64→    return resolve(owlClass.getIRI());
    65→  }
    66→
    67→  /**
    68→   * Resolves the short form name of an OWL named individual.
    69→   *
    70→   * @param individual the OWL named individual
    71→   * @return the short form name, never null
    72→   * @throws NullPointerException if individual is null
    73→   */
    74→  public String resolve(OWLNamedIndividual individual) {
    75→    Objects.requireNonNull(individual, "individual must not be null");
    76→    return resolve(individual.getIRI());
    77→  }
    78→
    79→  /**
    80→   * Resolves the short form name of an OWL entity.
    81→   *
    82→   * @param entity the OWL entity
    83→   * @return the short form name, never null
    84→   * @throws NullPointerException if entity is null
    85→   */
    86→  public String resolve(OWLEntity entity) {
    87→    Objects.requireNonNull(entity, "entity must not be null");
    88→    return resolve(entity.getIRI());
    89→  }
    90→
    91→  /**
    92→   * Resolves the short form name of any object with an IRI.
    93→   *
    94→   * @param hasIRI the object with an IRI
    95→   * @return the short form name, never null
    96→   * @throws NullPointerException if hasIRI is null
    97→   */
    98→  public String resolve(HasIRI hasIRI) {
    99→    Objects.requireNonNull(hasIRI, "hasIRI must not be null");
   100→    return resolve(hasIRI.getIRI());
   101→  }
   102→
   103→  /**
   104→   * Resolves the short form name of an IRI.
   105→   *
   106→   * @param iri the IRI
   107→   * @return the short form name, never null
   108→   * @throws NullPointerException if iri is null
   109→   */
   110→  public String resolve(IRI iri) {
   111→    Objects.requireNonNull(iri, "iri must not be null");
   112→    String shortForm = shortFormProvider.getShortForm(iri);
   113→    return Objects.requireNonNull(shortForm, "shortForm must not be null");
   114→  }
   115→}
