     4→import java.util.ArrayList;
     5→import java.util.HashMap;
     6→import java.util.List;
     7→import java.util.Map;
     8→import java.util.Optional;
     9→import org.semanticweb.owlapi.model.IRI;
    10→import org.semanticweb.owlapi.model.OWLClass;
    11→import org.semanticweb.owlapi.model.OWLClassExpression;
    12→import org.semanticweb.owlapi.model.OWLDatatype;
    13→import org.semanticweb.owlapi.model.OWLIndividual;
    14→import org.semanticweb.owlapi.model.OWLLiteral;
    15→import org.semanticweb.owlapi.model.OWLNamedIndividual;
    16→import org.semanticweb.owlapi.model.OWLObjectHasValue;
    17→import org.semanticweb.owlapi.model.OWLObjectOneOf;
    18→import org.semanticweb.owlapi.model.OWLOntology;
    19→import org.semanticweb.owlapi.search.EntitySearcher;
    20→
    21→/**
    22→ * Detects taxonomy patterns in OWL class expressions.
    23→ *
    24→ * <p>This class identifies four taxonomy patterns used in ontologies:
    25→ * <ul>
    26→ *   <li><b>Pattern A</b>: Inline enum with untyped individuals (owl:oneOf with no rdf:type)</li>
    27→ *   <li><b>Pattern B</b>: Typed individuals with metadata (owl:oneOf with rdf:type and annotations)</li>
    28→ *   <li><b>Pattern C</b>: Class-based taxonomy (named class without object property restrictions)</li>
    29→ *   <li><b>Pattern D</b>: SKOS taxonomy (subclass of skos:Concept or has skos:inScheme)</li>
    30→ * </ul>
    31→ *
    32→ * <p>Thread safety: This class is thread-safe if the underlying OWLOntology is not modified
    33→ * during detection.
    34→ *
    35→ * @see TaxonomyInfo
    36→ * @see TaxonomyPattern
    37→ */
    38→public class TaxonomyPatternDetector {
    39→
    40→  private final OWLOntology ontology;
    41→  private final PropertyNameResolver nameResolver;
    42→
    43→  /**
    44→   * Creates a new detector for the given ontology.
    45→   *
    46→   * @param ontology the ontology to analyze
    47→   */
    48→  public TaxonomyPatternDetector(OWLOntology ontology) {
    49→    this.ontology = ontology;
    50→    this.nameResolver = new PropertyNameResolver();
    51→  }
    52→
    53→  /**
    54→   * Creates a new detector with a shared name resolver.
    55→   *
    56→   * @param ontology     the ontology to analyze
    57→   * @param nameResolver the resolver for property/class names
    58→   */
    59→  public TaxonomyPatternDetector(OWLOntology ontology, PropertyNameResolver nameResolver) {
    60→    this.ontology = ontology;
    61→    this.nameResolver = nameResolver;
    62→  }
    63→
    64→  /**
    65→   * Detects if a filler class expression represents a taxonomy pattern.
    66→   *
    67→   * @param propertyName the property name this restriction is associated with
    68→   * @param filler       the filler class expression from a restriction
    69→   * @return detected taxonomy info, or empty if no taxonomy pattern found
    70→   */
    71→  public Optional<TaxonomyInfo> detect(String propertyName, OWLClassExpression filler) {
    72→    if (filler instanceof OWLObjectOneOf oneOf) {
    73→      return detectOneOfPattern(propertyName, oneOf);
    74→    } else if (filler.isNamed() && filler instanceof OWLClass targetClass) {
    75→      return detectClassPattern(propertyName, targetClass);
    76→    }
    77→    return Optional.empty();
    78→  }
    79→
    80→  /**
    81→   * Detects Pattern A or B from an owl:oneOf expression.
    82→   */
    83→  private Optional<TaxonomyInfo> detectOneOfPattern(String propertyName, OWLObjectOneOf oneOf) {
    84→    List<OWLNamedIndividual> individuals = oneOf.individuals()
    85→        .filter(ind -> ind instanceof OWLNamedIndividual)
    86→        .map(ind -> (OWLNamedIndividual) ind)
    87→        .toList();
    88→
    89→    if (individuals.isEmpty()) {
    90→      return Optional.empty();
    91→    }
    92→
    93→    boolean hasTypedIndividuals = individuals.stream()
    94→        .anyMatch(this::hasDomainClass);
    95→
    96→    if (hasTypedIndividuals) {
    97→      // Pattern B: typed individuals with metadata and property graphs
    98→      return Optional.of(buildPatternB(propertyName, individuals));
    99→    } else {
   100→      // Pattern A: untyped individuals (inline enum)
   101→      return Optional.of(TaxonomyInfo.patternA(propertyName, individuals));
   102→    }
   103→  }
   104→
   105→  /**
   106→   * Builds Pattern B taxonomy info with individual metadata and property graphs.
   107→   */
   108→  private TaxonomyInfo buildPatternB(String propertyName, List<OWLNamedIndividual> individuals) {
   109→    Map<String, TaxonomyInfo.IndividualMetadata> metadata = new HashMap<>();
   110→    List<TaxonomyInfo.IndividualGraph> individualGraphs = new ArrayList<>();
   111→
   112→    for (OWLNamedIndividual ind : individuals) {
   113→      OWLClass domainClass = getDomainClass(ind);
   114→      String codeValue = getAnnotationValue(ind, OntologyConstants.SKOS_NOTATION);
   115→      String displayName = getAnnotationValue(ind, OntologyConstants.SKOS_PREFLABEL);
   116→      String definition = getAnnotationValue(ind, OntologyConstants.SKOS_DEFINITION);
   117→      String indName = nameResolver.resolve(ind);
   118→      metadata.put(indName, new TaxonomyInfo.IndividualMetadata(
   119→          codeValue, displayName, definition, domainClass));
   120→
   121→      TaxonomyInfo.IndividualGraph graph = extractIndividualGraph(ind);
   122→      individualGraphs.add(graph);
   123→    }
   124→
   125→    return TaxonomyInfo.patternB(propertyName, individuals, metadata, individualGraphs);
   126→  }
   127→
   128→  /**
   129→   * Detects Pattern C or D from a named class.
   130→   */
   131→  private Optional<TaxonomyInfo> detectClassPattern(String propertyName, OWLClass targetClass) {
   132→    // Skip owl:Thing - it doesn't represent a taxonomy pattern
   133→    if (targetClass.isOWLThing()) {
   134→      return Optional.empty();
   135→    }
   136→
   137→    if (isSubClassOfSkosConcept(targetClass) || hasInSchemeRestriction(targetClass)) {
   138→      // Pattern D: SKOS taxonomy
   139→      OWLIndividual conceptScheme = findConceptScheme(targetClass);
   140→      List<OWLNamedIndividual> individuals = findSkosConceptIndividuals(targetClass);
   141→      return Optional.of(TaxonomyInfo.patternD(
   142→          propertyName, targetClass, individuals, conceptScheme));
   143→    } else if (!hasObjectPropertyRestrictions(targetClass)) {
   144→      // Pattern C: class-based taxonomy (no object property restrictions)
   145→      List<OWLNamedIndividual> individuals = findClassIndividuals(targetClass);
   146→      boolean hasHierarchy = hasSubclassHierarchy(targetClass);
   147→      return Optional.of(TaxonomyInfo.patternC(
   148→          propertyName, targetClass, individuals, hasHierarchy));
   149→    }
   150→
   151→    // Domain class with object property restrictions - not a taxonomy
   152→    return Optional.empty();
   153→  }
   154→
   155→  /**
   156→   * Checks if an individual has a domain class type (not owl:Thing).
   157→   */
   158→  private boolean hasDomainClass(OWLNamedIndividual individual) {
   159→    return EntitySearcher.getTypes(individual, ontology)
   160→        .anyMatch(type -> type.isNamed() && !type.isOWLThing());
   161→  }
   162→
   163→  /**
   164→   * Gets the domain class for an individual.
   165→   *
   166→   * @return the first named non-Thing class, or null if none
   167→   */
   168→  private OWLClass getDomainClass(OWLNamedIndividual individual) {
   169→    return EntitySearcher.getTypes(individual, ontology)
   170→        .filter(type -> type.isNamed() && !type.isOWLThing())
   171→        .map(OWLClassExpression::asOWLClass)
   172→        .findFirst()
   173→        .orElse(null);
   174→  }
   175→
   176→  /**
   177→   * Gets an annotation value for an individual, matching by short form to handle namespace
   178→   * flattening.
   179→   */
   180→  private String getAnnotationValue(OWLNamedIndividual individual, IRI annotationIRI) {
   181→    String shortForm = annotationIRI.getShortForm();
   182→    return EntitySearcher.getAnnotations(individual, ontology)
   183→        .filter(ann -> nameResolver.resolve(ann.getProperty()).equals(shortForm))
   184→        .findFirst()
   185→        .flatMap(ann -> ann.getValue().asLiteral())
   186→        .map(OWLLiteral::getLiteral)
   187→        .orElse(null);
   188→  }
   189→
   190→  /**
   191→   * Extracts an IndividualGraph for a Pattern B individual, including all property assertions.
   192→   */
   193→  private TaxonomyInfo.IndividualGraph extractIndividualGraph(OWLNamedIndividual individual) {
   194→    String code = getCodeValue(individual);
   195→    String displayName = getAnnotationValue(individual, OntologyConstants.SKOS_PREFLABEL);
   196→    String definition = getAnnotationValue(individual, OntologyConstants.SKOS_DEFINITION);
   197→
   198→    List<TaxonomyInfo.PropertyAssertion> assertions = new ArrayList<>();
   199→
   200→    // Extract data property assertions from axioms
   201→    ontology.dataPropertyAssertionAxioms(individual)
   202→        .forEach(axiom -> {
   203→          if (axiom.getProperty().isNamed()) {
   204→            String propName = nameResolver.resolve(axiom.getProperty().asOWLDataProperty());
   205→            OWLLiteral lit = axiom.getObject();
   206→            assertions.add(new TaxonomyInfo.PropertyAssertion(
   207→                propName,
   208→                lit.getLiteral(),
   209→                lit.getDatatype(),
   210→                null
   211→            ));
   212→          }
   213→        });
   214→
   215→    // Extract object property assertions from axioms
   216→    ontology.objectPropertyAssertionAxioms(individual)
   217→        .forEach(axiom -> {
   218→          if (axiom.getProperty().isNamed() && axiom.getObject().isNamed()) {
   219→            String propName = nameResolver.resolve(axiom.getProperty().asOWLObjectProperty());
   220→            assertions.add(new TaxonomyInfo.PropertyAssertion(
   221→                propName,
   222→                null,
   223→                null,
   224→                axiom.getObject().asOWLNamedIndividual()
   225→            ));
   226→          }
   227→        });
   228→
   229→    return new TaxonomyInfo.IndividualGraph(code, displayName, definition, assertions, individual);
   230→  }
   231→
   232→  /**
   233→   * Gets the code value for an individual: skos:notation if present, otherwise IRI local name.
   234→   */
   235→  private String getCodeValue(OWLNamedIndividual individual) {
   236→    String notation = getAnnotationValue(individual, OntologyConstants.SKOS_NOTATION);
   237→    return notation != null ? notation : nameResolver.resolve(individual);
   238→  }
   239→
   240→  /**
   241→   * Checks if a class is a subclass of skos:Concept.
   242→   */
   243→  private boolean isSubClassOfSkosConcept(OWLClass cls) {
   244→    return EntitySearcher.getSuperClasses(cls, ontology)
   245→        .anyMatch(superCls -> superCls.isNamed() &&
   246→            superCls.asOWLClass().getIRI().equals(OntologyConstants.SKOS_CONCEPT));
   247→  }
   248→
   249→  /**
   250→   * Checks if a class has a skos:inScheme restriction.
   251→   */
   252→  private boolean hasInSchemeRestriction(OWLClass cls) {
   253→    return ontology.subClassAxiomsForSubClass(cls)
   254→        .map(ax -> ax.getSuperClass())
   255→        .anyMatch(superCls -> {
   256→          if (superCls instanceof OWLObjectHasValue hasValue) {
   257→            return hasValue.getProperty().isNamed() &&
   258→                hasValue.getProperty().asOWLObjectProperty().getIRI()
   259→                    .equals(OntologyConstants.SKOS_IN_SCHEME);
   260→          }
   261→          return false;
   262→        });
   263→  }
   264→
   265→  /**
   266→   * Checks if a class has object property restrictions (indicating it's a domain class, not a
   267→   * taxonomy).
   268→   */
   269→  private boolean hasObjectPropertyRestrictions(OWLClass cls) {
   270→    return ontology.subClassAxiomsForSubClass(cls)
   271→        .map(ax -> ax.getSuperClass())
   272→        .anyMatch(superCls -> !superCls.getObjectPropertiesInSignature().isEmpty());
   273→  }
   274→
   275→  /**
   276→   * Checks if a class has subclasses (indicating a hierarchy).
   277→   */
   278→  private boolean hasSubclassHierarchy(OWLClass cls) {
   279→    return ontology.classesInSignature()
   280→        .anyMatch(subCls -> EntitySearcher.getSuperClasses(subCls, ontology)
   281→            .anyMatch(superCls -> superCls.isNamed() && superCls.asOWLClass().equals(cls)));
   282→  }
   283→
   284→  /**
   285→   * Finds the skos:ConceptScheme for a class via skos:inScheme restriction.
   286→   */
   287→  private OWLIndividual findConceptScheme(OWLClass cls) {
   288→    return ontology.subClassAxiomsForSubClass(cls)
   289→        .map(ax -> ax.getSuperClass())
   290→        .filter(superCls -> superCls instanceof OWLObjectHasValue)
   291→        .map(superCls -> (OWLObjectHasValue) superCls)
   292→        .filter(hasValue -> hasValue.getProperty().isNamed() &&
   293→            hasValue.getProperty().asOWLObjectProperty().getIRI()
   294→                .equals(OntologyConstants.SKOS_IN_SCHEME))
   295→        .map(OWLObjectHasValue::getFiller)
   296→        .findFirst()
   297→        .orElse(null);
   298→  }
   299→
   300→  /**
   301→   * Finds all individuals that are instances of the given SKOS concept class.
   302→   */
   303→  private List<OWLNamedIndividual> findSkosConceptIndividuals(OWLClass cls) {
   304→    List<OWLNamedIndividual> result = new ArrayList<>();
   305→    EntitySearcher.getIndividuals(cls, ontology)
   306→        .filter(ind -> ind instanceof OWLNamedIndividual)
   307→        .map(ind -> (OWLNamedIndividual) ind)
   308→        .forEach(result::add);
   309→    return result;
   310→  }
   311→
   312→  /**
   313→   * Finds all individuals of a class and its subclasses.
   314→   */
   315→  private List<OWLNamedIndividual> findClassIndividuals(OWLClass cls) {
   316→    List<OWLNamedIndividual> result = new ArrayList<>();
   317→
   318→    // Direct instances
   319→    EntitySearcher.getIndividuals(cls, ontology)
   320→        .filter(ind -> ind instanceof OWLNamedIndividual)
   321→        .map(ind -> (OWLNamedIndividual) ind)
   322→        .forEach(result::add);
   323→
   324→    // Instances of subclasses
   325→    ontology.classesInSignature()
   326→        .filter(subCls -> EntitySearcher.getSuperClasses(subCls, ontology)
   327→            .anyMatch(superCls -> superCls.isNamed() && superCls.asOWLClass().equals(cls)))
   328→        .forEach(subCls -> EntitySearcher.getIndividuals(subCls, ontology)
   329→            .filter(ind -> ind instanceof OWLNamedIndividual)
   330→            .map(ind -> (OWLNamedIndividual) ind)
   331→            .forEach(result::add));
   332→
   333→    return result;
   334→  }
   335→}
