     3→import com.grl.component.asg.configuration.YamlConfig;
     4→import com.grl.component.owl.OntologyUtil;
     5→import com.grl.component.schema.PropertyNameResolver;
     6→import com.grl.component.schema.RestrictionInfo;
     7→import com.grl.component.schema.TaxonomyInfo;
     8→import com.grl.component.schema.TaxonomyPattern;
     9→import io.swagger.v3.oas.models.media.ArraySchema;
    10→import io.swagger.v3.oas.models.media.ComposedSchema;
    11→import io.swagger.v3.oas.models.media.ObjectSchema;
    12→import io.swagger.v3.oas.models.media.Schema;
    13→import io.swagger.v3.oas.models.media.StringSchema;
    14→import java.util.ArrayList;
    15→import java.util.HashSet;
    16→import java.util.List;
    17→import java.util.Map;
    18→import java.util.Set;
    19→import org.semanticweb.owlapi.model.OWLDatatype;
    20→import org.semanticweb.owlapi.model.OWLClass;
    21→import org.semanticweb.owlapi.model.OWLLiteral;
    22→import org.semanticweb.owlapi.model.OWLNamedIndividual;
    23→import org.semanticweb.owlapi.model.OWLOntology;
    24→import org.semanticweb.owlapi.search.EntitySearcher;
    25→
    26→/**
    27→ * Maps detected taxonomy patterns to OpenAPI schemas.
    28→ *
    29→ * <p>This mapper generates OpenAPI schemas based on the taxonomy patterns detected
    30→ * by SchemaVisitor. Each pattern produces a different schema structure:
    31→ *
    32→ * <ul>
    33→ *   <li><b>Pattern A</b>: Inline StringSchema with enum values</li>
    34→ *   <li><b>Pattern B</b>: StringSchema with enum values (from codeValue or label)</li>
    35→ *   <li><b>Pattern C</b>: $ref to schema in components/schemas</li>
    36→ *   <li><b>Pattern D</b>: $ref to Coding schema in components/schemas</li>
    37→ * </ul>
    38→ *
    39→ * @see TaxonomyPattern
    40→ * @see TaxonomyInfo
    41→ */
    42→public class TaxonomyPatternMapper {
    43→
    44→  private final PropertyNameResolver nameResolver = new PropertyNameResolver();
    45→  private final MappingContext context;
    46→  private final TaxonomyInfo info;
    47→  private final Set<RestrictionInfo> restrictions;
    48→  private final String description;
    49→  private final String label;
    50→
    51→  private final boolean isArray;
    52→  private final boolean isRequired;
    53→
    54→  public TaxonomyPatternMapper(
    55→      MappingContext context,
    56→      TaxonomyInfo info,
    57→      Set<RestrictionInfo> restrictions,
    58→      String description,
    59→      String label) {
    60→    this.context = context;
    61→    this.info = info;
    62→    this.restrictions = restrictions;
    63→    this.description = description;
    64→    this.label = label;
    65→
    66→    YamlConfig config = context.getConfig();
    67→    this.isArray = restrictions != null &&
    68→        restrictions.stream().anyMatch(RestrictionInfo::impliesArray);
    69→    this.isRequired = config.isEnforceRequiredness() &&
    70→        restrictions != null && restrictions.stream().anyMatch(RestrictionInfo::impliesRequired);
    71→  }
    72→
    73→  public String getName() {
    74→    return info.propertyName();
    75→  }
    76→
    77→  public boolean isRequired() {
    78→    return isRequired;
    79→  }
    80→
    81→  /**
    82→   * Generates the OpenAPI schema based on the detected taxonomy pattern.
    83→   */
    84→  public Schema<?> getSchema() {
    85→    return switch (info.pattern()) {
    86→      case PATTERN_A -> mapPatternA();
    87→      case PATTERN_B -> mapPatternB();
    88→      case PATTERN_C -> mapPatternC();
    89→      case PATTERN_D -> mapPatternD();
    90→      case NONE -> throw new IllegalArgumentException(
    91→          "Cannot map NONE pattern to schema for property: " + info.propertyName());
    92→    };
    93→  }
    94→
    95→  /**
    96→   * Pattern A: Inline enumeration with untyped individuals.
    97→   * Generates StringSchema with enum values from individual labels.
    98→   */
    99→  private Schema<?> mapPatternA() {
   100→    List<String> enumValues = info.individuals().stream()
   101→        .map(ind -> OntologyUtil.getTitle(ind, context.getOntology()))
   102→        .toList();
   103→
   104→    StringSchema enumSchema = new StringSchema();
   105→    enumSchema.setDescription(description);
   106→    enumSchema.setEnum(enumValues);
   107→
   108→    return wrapInArrayIfNeeded(enumSchema);
   109→  }
   110→
   111→  /**
   112→   * Pattern B: Typed individuals with metadata.
   113→   * Generates oneOf with const objects when maxIndividualDepth >= 1,
   114→   * or falls back to simple string enum when maxIndividualDepth == 0.
   115→   */
   116→  private Schema<?> mapPatternB() {
   117→    int maxDepth = context.getMaxIndividualDepth();
   118→
   119→    // Backward compatibility: depth 0 = simple string enum (old behavior)
   120→    if (maxDepth == 0) {
   121→      return mapPatternBLegacy();
   122→    }
   123→
   124→    // Generate oneOf with const objects
   125→    List<TaxonomyInfo.IndividualGraph> graphs = info.individualGraphs();
   126→    if (graphs.isEmpty()) {
   127→      // Fallback if no graphs extracted (shouldn't happen normally)
   128→      return mapPatternBLegacy();
   129→    }
   130→
   131→    List<Schema> individualSchemas = new ArrayList<>();
   132→    for (TaxonomyInfo.IndividualGraph graph : graphs) {
   133→      Schema<?> indSchema = buildIndividualSchema(graph, maxDepth, new HashSet<>());
   134→      individualSchemas.add(indSchema);
   135→    }
   136→
   137→    ComposedSchema oneOfSchema = new ComposedSchema();
   138→    oneOfSchema.setOneOf(individualSchemas);
   139→    oneOfSchema.setDescription(description);
   140→
   141→    return wrapInArrayIfNeeded(oneOfSchema);
   142→  }
   143→
   144→  /**
   145→   * Legacy Pattern B: Simple string enum (for backward compatibility with maxIndividualDepth=0).
   146→   */
   147→  private Schema<?> mapPatternBLegacy() {
   148→    List<String> enumValues = new ArrayList<>();
   149→
   150→    for (OWLNamedIndividual ind : info.individuals()) {
   151→      String indName = nameResolver.resolve(ind);
   152→      TaxonomyInfo.IndividualMetadata meta = info.metadata().get(indName);
   153→
   154→      // Use codeValue if available, otherwise use label
   155→      String codeValue = meta != null && meta.codeValue() != null
   156→          ? meta.codeValue()
   157→          : OntologyUtil.getTitle(ind, context.getOntology());
   158→      enumValues.add(codeValue);
   159→    }
   160→
   161→    StringSchema enumSchema = new StringSchema();
   162→    enumSchema.setDescription(description);
   163→    enumSchema.setEnum(enumValues);
   164→
   165→    return wrapInArrayIfNeeded(enumSchema);
   166→  }
   167→
   168→  /**
   169→   * Builds an ObjectSchema for an individual with const values for all properties.
   170→   *
   171→   * @param graph the individual graph to convert
   172→   * @param remainingDepth how many more levels of object properties to expand
   173→   * @param visited set of individual codes already visited (for cycle detection)
   174→   */
   175→  private Schema<?> buildIndividualSchema(
   176→      TaxonomyInfo.IndividualGraph graph,
   177→      int remainingDepth,
   178→      Set<String> visited) {
   179→
   180→    ObjectSchema schema = new ObjectSchema();
   181→
   182→    // Add code field
   183→    Schema<String> codeSchema = new StringSchema();
   184→    codeSchema.setConst(graph.code());
   185→    schema.addProperty("code", codeSchema);
   186→
   187→    // Add displayName if present
   188→    if (graph.displayName() != null) {
   189→      Schema<String> displaySchema = new StringSchema();
   190→      displaySchema.setConst(graph.displayName());
   191→      schema.addProperty("displayName", displaySchema);
   192→    }
   193→
   194→    // Add definition if present
   195→    if (graph.definition() != null) {
   196→      Schema<String> defSchema = new StringSchema();
   197→      defSchema.setConst(graph.definition());
   198→      schema.addProperty("definition", defSchema);
   199→    }
   200→
   201→    // Add property assertions
   202→    for (TaxonomyInfo.PropertyAssertion assertion : graph.assertions()) {
   203→      Schema<?> propSchema;
   204→
   205→      if (assertion.isDataProperty()) {
   206→        // Data property: create const schema with type
   207→        propSchema = new Schema<>();
   208→        propSchema.setConst(assertion.literalValue());
   209→        propSchema.setType(mapDatatypeToJsonType(assertion.datatype()));
   210→      } else if (assertion.isObjectProperty() && remainingDepth > 1) {
   211→        // Object property with depth remaining: try to expand
   212→        OWLNamedIndividual target = assertion.objectValue();
   213→        String targetCode = getIndividualCode(target);
   214→
   215→        if (visited.contains(targetCode)) {
   216→          // Cycle detection - use code reference instead of infinite recursion
   217→          propSchema = new StringSchema();
   218→          propSchema.setConst(targetCode);
   219→        } else {
   220→          visited.add(targetCode);
   221→          TaxonomyInfo.IndividualGraph targetGraph = extractIndividualGraphDirect(target);
   222→          propSchema = buildIndividualSchema(targetGraph, remainingDepth - 1, visited);
   223→          visited.remove(targetCode);
   224→        }
   225→      } else if (assertion.isObjectProperty()) {
   226→        // Max depth reached or remaining depth = 1 - use code reference
   227→        String targetCode = getIndividualCode(assertion.objectValue());
   228→        propSchema = new StringSchema();
   229→        propSchema.setConst(targetCode);
   230→      } else {
   231→        continue; // Skip invalid assertions
   232→      }
   233→
   234→      schema.addProperty(assertion.propertyName(), propSchema);
   235→    }
   236→
   237→    return schema;
   238→  }
   239→
   240→  /**
   241→   * Maps XSD datatype to JSON Schema type.
   242→   */
   243→  private String mapDatatypeToJsonType(OWLDatatype datatype) {
   244→    if (datatype == null) {
   245→      return "string";
   246→    }
   247→    String shortForm = datatype.getIRI().getShortForm();
   248→    return switch (shortForm) {
   249→      case "integer", "int", "long", "short", "byte", "nonNegativeInteger",
   250→           "positiveInteger", "nonPositiveInteger", "negativeInteger",
   251→           "unsignedInt", "unsignedLong", "unsignedShort", "unsignedByte" -> "integer";
   252→      case "decimal", "float", "double" -> "number";
   253→      case "boolean" -> "boolean";
   254→      default -> "string";
   255→    };
   256→  }
   257→
   258→  /**
   259→   * Gets the code value for an individual (skos:notation or IRI local name).
   260→   */
   261→  private String getIndividualCode(OWLNamedIndividual individual) {
   262→    OWLOntology ontology = context.getOntology();
   263→    return EntitySearcher.getAnnotations(individual, ontology)
   264→        .filter(ann -> ann.getProperty().getIRI().getShortForm().equals("notation"))
   265→        .findFirst()
   266→        .flatMap(ann -> ann.getValue().asLiteral())
   267→        .map(lit -> lit.getLiteral())
   268→        .orElse(nameResolver.resolve(individual));
   269→  }
   270→
   271→  /**
   272→   * Extracts an IndividualGraph directly from an OWL individual.
   273→   * Used for nested expansion of object property targets.
   274→   */
   275→  private TaxonomyInfo.IndividualGraph extractIndividualGraphDirect(OWLNamedIndividual individual) {
   276→    OWLOntology ontology = context.getOntology();
   277→
   278→    String code = getIndividualCode(individual);
   279→    String displayName = getAnnotationValue(individual, "prefLabel");
   280→    String definition = getAnnotationValue(individual, "definition");
   281→
   282→    List<TaxonomyInfo.PropertyAssertion> assertions = new ArrayList<>();
   283→
   284→    // Extract data property assertions from axioms
   285→    ontology.dataPropertyAssertionAxioms(individual)
   286→        .forEach(axiom -> {
   287→          if (axiom.getProperty().isNamed()) {
   288→            String propName = nameResolver.resolve(axiom.getProperty().asOWLDataProperty());
   289→            OWLLiteral lit = axiom.getObject();
   290→            assertions.add(new TaxonomyInfo.PropertyAssertion(
   291→                propName,
   292→                lit.getLiteral(),
   293→                lit.getDatatype(),
   294→                null
   295→            ));
   296→          }
   297→        });
   298→
   299→    // Extract object property assertions from axioms
   300→    ontology.objectPropertyAssertionAxioms(individual)
   301→        .forEach(axiom -> {
   302→          if (axiom.getProperty().isNamed() && axiom.getObject().isNamed()) {
   303→            String propName = nameResolver.resolve(axiom.getProperty().asOWLObjectProperty());
   304→            assertions.add(new TaxonomyInfo.PropertyAssertion(
   305→                propName,
   306→                null,
   307→                null,
   308→                axiom.getObject().asOWLNamedIndividual()
   309→            ));
   310→          }
   311→        });
   312→
   313→    return new TaxonomyInfo.IndividualGraph(code, displayName, definition, assertions, individual);
   314→  }
   315→
   316→  /**
   317→   * Gets annotation value by short form name.
   318→   */
   319→  private String getAnnotationValue(OWLNamedIndividual individual, String shortForm) {
   320→    OWLOntology ontology = context.getOntology();
   321→    return EntitySearcher.getAnnotations(individual, ontology)
   322→        .filter(ann -> ann.getProperty().getIRI().getShortForm().equals(shortForm))
   323→        .findFirst()
   324→        .flatMap(ann -> ann.getValue().asLiteral())
   325→        .map(lit -> lit.getLiteral())
   326→        .orElse(null);
   327→  }
   328→
   329→  /**
   330→   * Pattern C: Class-based taxonomy (extensible).
   331→   * Generates $ref to schema in components/schemas.
   332→   */
   333→  private Schema<?> mapPatternC() {
   334→    OWLClass targetClass = info.targetClass();
   335→    if (targetClass == null) {
   336→      throw new IllegalStateException("Pattern C requires a target class");
   337→    }
   338→
   339→    String schemaName = nameResolver.resolve(targetClass);
   340→
   341→    // Create or get the taxonomy schema in components/schemas
   342→    createTaxonomySchemaIfNeeded(schemaName, targetClass);
   343→
   344→    // Create reference to the taxonomy schema
   345→    Schema<?> refSchema = new Schema<>();
   346→    refSchema.set$ref("#/components/schemas/" + schemaName);
   347→
   348→    return wrapInArrayIfNeeded(refSchema);
   349→  }
   350→
   351→  /**
   352→   * Pattern D: SKOS taxonomy (FHIR-compatible).
   353→   * Generates $ref to Coding schema in components/schemas.
   354→   */
   355→  private Schema<?> mapPatternD() {
   356→    OWLClass targetClass = info.targetClass();
   357→    if (targetClass == null) {
   358→      throw new IllegalStateException("Pattern D requires a target class");
   359→    }
   360→
   361→    String schemaName = nameResolver.resolve(targetClass) + "Coding";
   362→
   363→    // Create or get the SKOS Coding schema
   364→    createSkosCodingSchemaIfNeeded(schemaName, targetClass);
   365→
   366→    // Create reference to the Coding schema
   367→    Schema<?> refSchema = new Schema<>();
   368→    refSchema.set$ref("#/components/schemas/" + schemaName);
   369→
   370→    return wrapInArrayIfNeeded(refSchema);
   371→  }
   372→
   373→  private Schema<?> wrapInArrayIfNeeded(Schema<?> itemSchema) {
   374→    if (isArray) {
   375→      ArraySchema arraySchema = new ArraySchema();
   376→      arraySchema.setName(info.propertyName());
   377→      arraySchema.setTitle(label);
   378→
   379→      // Apply cardinality restrictions
   380→      if (restrictions != null) {
   381→        for (RestrictionInfo restriction : restrictions) {
   382→          restriction.applyToArraySchema(arraySchema);
   383→        }
   384→      }
   385→
   386→      arraySchema.setItems(itemSchema);
   387→      return arraySchema;
   388→    } else {
   389→      itemSchema.setName(info.propertyName());
   390→      itemSchema.setTitle(label);
   391→      return itemSchema;
   392→    }
   393→  }
   394→
   395→  /**
   396→   * Creates the taxonomy schema in components/schemas for Pattern C.
   397→   */
   398→  private void createTaxonomySchemaIfNeeded(String schemaName, OWLClass targetClass) {
   399→    Map<String, Schema<?>> schemas = context.getSchemaByRef();
   400→    if (schemas.containsKey(schemaName)) {
   401→      return;
   402→    }
   403→
   404→    OWLOntology ontology = context.getOntology();
   405→
   406→    ObjectSchema taxonomySchema = new ObjectSchema();
   407→    taxonomySchema.setName(schemaName);
   408→    taxonomySchema.setTitle(OntologyUtil.getTitle(targetClass, ontology));
   409→    taxonomySchema.setDescription(OntologyUtil.getDescription(targetClass, ontology));
   410→
   411→    // Add code property with enum values
   412→    List<String> enumValues = info.individuals().stream()
   413→        .map(ind -> {
   414→          // Try to get codeValue annotation, fallback to label
   415→          String codeVal = getCodeValue(ind, ontology);
   416→          return codeVal != null ? codeVal : OntologyUtil.getTitle(ind, ontology);
   417→        })
   418→        .toList();
   419→
   420→    StringSchema codeSchema = new StringSchema();
   421→    codeSchema.setDescription("The code value");
   422→    if (!enumValues.isEmpty()) {
   423→      codeSchema.setEnum(enumValues);
   424→    }
   425→    taxonomySchema.addProperty("code", codeSchema);
   426→
   427→    // Add displayName property
   428→    StringSchema displayNameSchema = new StringSchema();
   429→    displayNameSchema.setDescription("Human-readable display name");
   430→    taxonomySchema.addProperty("displayName", displayNameSchema);
   431→
   432→    schemas.put(schemaName, taxonomySchema);
   433→  }
   434→
   435→  /**
   436→   * Creates the SKOS Coding schema in components/schemas for Pattern D.
   437→   */
   438→  private void createSkosCodingSchemaIfNeeded(String schemaName, OWLClass targetClass) {
   439→    Map<String, Schema<?>> schemas = context.getSchemaByRef();
   440→    if (schemas.containsKey(schemaName)) {
   441→      return;
   442→    }
   443→
   444→    OWLOntology ontology = context.getOntology();
   445→
   446→    ObjectSchema codingSchema = new ObjectSchema();
   447→    codingSchema.setName(schemaName);
   448→    codingSchema.setTitle(OntologyUtil.getTitle(targetClass, ontology) + " Coding");
   449→    codingSchema.setDescription("SKOS-based coding for " +
   450→        OntologyUtil.getDescription(targetClass, ontology));
   451→
   452→    // Add system property (constant for the CodeSystem)
   453→    StringSchema systemSchema = new StringSchema();
   454→    systemSchema.setDescription("The CodeSystem URL");
   455→    codingSchema.addProperty("system", systemSchema);
   456→
   457→    // Add code property
   458→    StringSchema codeSchema = new StringSchema();
   459→    codeSchema.setDescription("The code value (skos:notation)");
   460→    codingSchema.addProperty("code", codeSchema);
   461→
   462→    // Add display property
   463→    StringSchema displaySchema = new StringSchema();
   464→    displaySchema.setDescription("Human-readable display (skos:prefLabel)");
   465→    codingSchema.addProperty("display", displaySchema);
   466→
   467→    // Add required fields
   468→    codingSchema.addRequiredItem("code");
   469→
   470→    schemas.put(schemaName, codingSchema);
   471→  }
   472→
   473→  private String getCodeValue(OWLNamedIndividual individual, OWLOntology ontology) {
   474→    // Look for codeValue or skos:notation annotation
   475→    return EntitySearcher.getAnnotations(individual, ontology)
   476→        .filter(ann -> {
   477→          String propName = ann.getProperty().getIRI().getShortForm();
   478→          return propName.equals("codeValue") || propName.equals("notation");
   479→        })
   480→        .findFirst()
   481→        .flatMap(ann -> ann.getValue().asLiteral())
   482→        .map(lit -> lit.getLiteral())
   483→        .orElse(null);
   484→  }
   485→
   486→}
