    15→import io.swagger.v3.oas.models.media.Schema;
    16→import io.swagger.v3.oas.models.media.StringSchema;
    17→import java.util.List;
    18→import java.util.Map;
    19→import java.util.Optional;
    20→import java.util.Set;
    21→import javax.annotation.Nullable;
    22→import org.apache.commons.collections.CollectionUtils;
    23→
    24→public class DataPropertyMapper {
    25→
    26→  private static final Map<String, String> dataTypes = Map.ofEntries(
    27→      Map.entry("ENTITIES", "string"), Map.entry(
    28→          "ENTITY", "string"), Map.entry("ID", "string"), Map.entry("IDREF", "string"),
    29→      Map.entry("IDREFS", "string"),
    30→      Map.entry("NCName", "string"), Map.entry("NMTOKEN", "string"),
    31→      Map.entry("NMTOKENS", "string"), Map.entry(
    32→          "NOTATION", "string"), Map.entry("Name", "string"), Map.entry("QName", "string"),
    33→      Map.entry("anySimpleType"
    34→          , "string"), Map.entry("anyType", "string"), Map.entry("anyURI", "string"),
    35→      Map.entry("base64Binary",
    36→          "string"), Map.entry("boolean", "boolean"), Map.entry("byte", "integer"),
    37→      Map.entry("date", "string"),
    38→      Map.entry("dateTime", "dateTime"), Map.entry("dateTimeStamp", "dateTime"),
    39→      Map.entry("decimal", "number"),
    40→      Map.entry("double", "number"), Map.entry("duration", "string"), Map.entry("float", "number"),
    41→      Map.entry("gDay",
    42→          "string"), Map.entry("gMonth", "string"), Map.entry("gMonthYear", "string"),
    43→      Map.entry("gYear", "string"),
    44→      Map.entry("gYearMonth", "string"), Map.entry("hexBinary", "string"),
    45→      Map.entry("int", "integer"), Map.entry(
    46→          "integer", "integer"), Map.entry("language", "string"), Map.entry("long", "integer"),
    47→      Map.entry(
    48→          "negativeInteger", "integer"), Map.entry("nonNegativeInteger", "integer"), Map.entry(
    49→          "nonPositiveInteger", "integer"), Map.entry("normalizedString", "string"), Map.entry(
    50→          "positiveInteger", "integer"), Map.entry("short", "integer"),
    51→      Map.entry("string", "string"),
    52→      Map.entry("time", "string"), Map.entry("token", "string"),
    53→      Map.entry("unsignedByte", "integer"), Map.entry(
    54→          "unsignedInt", "integer"), Map.entry("unsignedLong", "integer"),
    55→      Map.entry("unsignedShort", "integer"),
    56→      Map.entry("langString", "string"), Map.entry("Literal", "string"));
    57→
    58→  private static String getDataType(String key) {
    59→    return dataTypes.get(key);
    60→  }
    61→
    62→  private static final String STRING_TYPE = "string";
    63→  private static final String NUMBER_TYPE = "number";
    64→  private static final String INTEGER_TYPE = "integer";
    65→  private static final String BOOLEAN_TYPE = "boolean";
    66→  private static final String DATETIME_TYPE = "dateTime";
    67→
    68→  private final String name;
    69→  final String label;
    70→  final String description;
    71→  final Object exampleValue;
    72→  private final List<String> type;
    73→  private final Boolean array;
    74→  private Boolean isRequired;
    75→  private final Set<RestrictionInfo> restrictions;
    76→  private final List<String> valuesFromDataRestrictions_ranges;
    77→
    78→  public Boolean isRequired() {
    79→    return isRequired;
    80→  }
    81→
    82→  /**
    83→   * Apply an example object the given schema. If we have an example object provided on construction
    84→   * we use it, otherwise apply a heuristic based on the type/format of the schema to get an
    85→   * appropriate example.
    86→   *
    87→   * @param parentSchema if this is composed (i.e. an array) the example will be applied to the
    88→   *                     outer schema with a note that it is an array
    89→   * @param <T>          schema to apply example to
    90→   * @return schema with example
    91→   */
    92→  private <T extends Schema<?>> T withExample(T parentSchema) {
    93→    boolean isArray = parentSchema.getType() != null && parentSchema.getType().equals("array");
    94→    Schema<?> schema = isArray ? parentSchema.getItems() : parentSchema;
    95→
    96→    // Get schema type, handling null
    97→    String schemaType = schema.getType();
    98→    if (schemaType == null) {
    99→      return parentSchema;
   100→    }
   101→
   102→    Optional.ofNullable(exampleValue).or(() -> Optional.ofNullable(switch (schemaType) {
   103→      case "string" -> {
   104→        String format = schema.getFormat();
   105→        yield format == null ? name + " string value" : switch (format) {
   106→          case "uri" -> "http://www.example.com";
   107→          case "date" -> "2025-01-15";
   108→          case "date-time" -> "2025-01-15T14:55:58+00:00";
   109→          case "time" -> "14:55:58+00:00";
   110→          case "duration" -> "P3Y6M4DT12H30M5S";
   111→          case "byte" -> "Ynl0ZSBhcnJvdw==";
   112→          default -> name + " string value";
   113→        };
   114→      }
   115→      case "number" -> 1.1;
   116→      case "integer" -> 1;
   117→      case "boolean" -> true;
   118→      default -> null;
   119→    })).ifPresent(schema::setExample);
   120→    return parentSchema;
   121→  }
   122→
   123→  public DataPropertyMapper(YamlConfig config, String name, String label, String description,
   124→      @Nullable Object exampleValue, Set<RestrictionInfo> restrictions,
   125→      List<String> valuesFromDataRestrictions_ranges, List<String> type) {
   126→    this.name = name;
   127→    this.label = label;
   128→    this.description = description;
   129→    this.exampleValue = exampleValue;
   130→    this.type = type;
   131→    this.restrictions = restrictions;
   132→    this.valuesFromDataRestrictions_ranges = valuesFromDataRestrictions_ranges;
   133→
   134→    // Compute array and required from restrictions
   135→    this.array =
   136→        restrictions != null && restrictions.stream().anyMatch(RestrictionInfo::impliesArray);
   137→    this.isRequired = config.isEnforceRequiredness() &&
   138→        restrictions != null && restrictions.stream().anyMatch(RestrictionInfo::impliesRequired);
   139→  }
   140→
   141→  public Schema<?> getSchemaByDataProperty() {
   142→    Schema<?> schema = withExample(createSchema());
   143→    schema.setName(this.name);
   144→    schema.setTitle(this.label);
   145→    return schema;
   146→  }
   147→
   148→  private Schema<?> createSchema() {
   149→
   150→    if (this.type.isEmpty()) {
   151→      return (this.array) ? this.arraySchema(new StringSchema())
   152→          : this.nonArraySchema(new StringSchema());
   153→    } else if (this.type.size() > 1) {
   154→      return (this.array) ? this.composedSchema() : this.nonArraySchema(new Schema<>());
   155→    }
   156→
   157→    String schemaType = getDataType(this.type.getFirst());
   158→    if (schemaType == null) {
   159→      throw new RuntimeException("property " + this.name + " type " + this.type);
   160→    }
   161→
   162→    //return (this.array) ? this.arraySchema(new Schema<>()) : this.nonArraySchema(new Schema<>());
   163→    return switch (schemaType) {
   164→      case STRING_TYPE -> (this.array) ? this.arraySchema(new StringSchema())
   165→          : this.nonArraySchema(new StringSchema());
   166→      case NUMBER_TYPE -> (this.array) ? this.arraySchema(new NumberSchema())
   167→          : this.nonArraySchema(new NumberSchema());
   168→      case INTEGER_TYPE -> (this.array) ? this.arraySchema(new IntegerSchema())
   169→          : this.nonArraySchema(new IntegerSchema());
   170→      case BOOLEAN_TYPE -> (this.array) ? this.arraySchema(new BooleanSchema())
   171→          : this.nonArraySchema(new BooleanSchema());
   172→      case DATETIME_TYPE -> (this.array) ? this.arraySchema(new DateTimeSchema())
   173→          : this.nonArraySchema(new DateTimeSchema());
   174→      default -> throw new RuntimeException("datatype mapping failed " + this.type.getFirst());
   175→    };
   176→  }
   177→
   178→  /**
   179→   * Generate a range of multiple values depending on the range axiom
   180→   *
   181→   * @return An ArraySchema: including a composedSchema with a list of items for anyOf, allOf restrictions.
   182→   */
   183→  private ArraySchema composedSchema() {
   184→    ArraySchema array = new ArraySchema();
   185→    Schema<?> schema;
   186→    ComposedSchema composedSchema = new ComposedSchema();
   187→    array.setDescription(description);
   188→
   189→    // Operations for managing boolean combinations
   190→    for (RestrictionInfo restriction : this.restrictions) {
   191→      for (String item : this.type) {
   192→        switch (getDataType(item)) {
   193→          case STRING_TYPE:
   194→            schema = new StringSchema();
   195→
   196→            if (item.equals("anyURI")) {
   197→              schema.format("uri");
   198→            } else if (item.equals("byte")) {
   199→              schema.format("byte");
   200→            }
   201→
   202→            break;
   203→          case NUMBER_TYPE:
   204→            schema = new NumberSchema().example(1.1);
   205→
   206→            if (item.equals("float")) {
   207→              schema.format("double");
   208→            } else if (item.equals("double")) {
   209→              schema.format("double");
   210→            } else {
   211→              schema.format("number");
   212→            }
   213→
   214→            break;
   215→          case INTEGER_TYPE:
   216→            schema = new IntegerSchema();
   217→            if (item.equals("long")) {
   218→              schema.format("int64");
   219→            }
   220→            break;
   221→          case BOOLEAN_TYPE:
   222→            schema = new BooleanSchema();
   223→            break;
   224→          case DATETIME_TYPE:
   225→            schema = withExample(new DateTimeSchema());
   226→            break;
   227→          default:
   228→            throw new RuntimeException("datatype mapping failed " + this.type.getFirst());
   229→            //schema = new Schema<>();
   230→        }
   231→        isRequired |= restriction.impliesRequired();
   232→        switch (restriction) {
   233→          case UnionOf unionOf -> composedSchema.addAnyOfItem(withExample(schema));
   234→          case IntersectionOf intersectionOf -> composedSchema.addAllOfItem(withExample(schema));
   235→          default -> {
   236→            // Other restriction types (DataSomeValuesFrom, etc.) don't affect composed schemas
   237→            // They are handled in applySchemaRestrictions()
   238→          }
   239→        }
   240→      }
   241→    }
   242→
   243→    array.setItems(composedSchema);
   244→    return array;
   245→  }
   246→
   247→  private Schema<?> nonArraySchema(Schema<?> base) {
   248→    base.setDescription(this.description);
   249→
   250→    this.applySchemaRestrictions(base);
   251→    return base;
   252→  }
   253→
   254→  private ArraySchema arraySchema(Schema<?> base) {
   255→    ArraySchema array = new ArraySchema();
   256→    array.setDescription(this.description);
   257→
   258→    if (this.restrictions.stream().anyMatch(r -> r instanceof RestrictionInfo.ComplementOf)) {
   259→      Schema<?> schema = new Schema<>();
   260→      Schema<?> complementOf = new Schema<>();
   261→      complementOf.setType(getDataType(this.type.getFirst()));
   262→      complementOf.setFormat(this.type.getFirst());
   263→      schema.setNot(complementOf);
   264→      array.setItems(schema);
   265→      return array;
   266→    }
   267→
   268→    // Apply non-cardinality restrictions to the base (items) schema
   269→    this.applySchemaRestrictions(base);
   270→
   271→    // Apply cardinality restrictions directly to the array schema
   272→    for (RestrictionInfo restriction : this.restrictions) {
   273→      restriction.applyToArraySchema(array);
   274→    }
   275→
   276→    array.setItems(base);
   277→
   278→    return array;
   279→  }
   280→
   281→  public String getName() {
   282→    return name;
   283→  }
   284→
   285→  private void applySchemaRestrictions(Schema<?> base) {
   286→    if (base.getType().equals("array")) {
   287→      if (base instanceof ArraySchema arraySchema) {
   288→        for (RestrictionInfo restriction : this.restrictions) {
   289→          restriction.applyToArraySchema(arraySchema);
   290→        }
   291→      }
   292→    } else {
   293→      for (RestrictionInfo restriction : this.restrictions) {
   294→        isRequired |= restriction.impliesRequired();
   295→        switch (restriction) {
   296→          case DataHasValue data -> base.setDefault(data.expression().getFiller().getLiteral());
   297→          case DataOneOf _dataOneOf -> {
   298→            if (CollectionUtils.isNotEmpty(this.valuesFromDataRestrictions_ranges)) {
   299→              if (base instanceof StringSchema stringSchema) {
   300→                this.valuesFromDataRestrictions_ranges.stream().sorted()
   301→                    .forEach(stringSchema::addEnumItemObject);
   302→              }
   303→            }
   304→          }
   305→          default -> {
   306→            // nothing to do
   307→          }
   308→        }
   309→      }
   310→    }
   311→  }
   312→
   313→}

