    11→/**
    12→ * Predicate for matching uris on ontology entities, short and logform versions of each
    13→ */
    14→public class WithIRI implements Predicate<HasIRI> {
    15→
    16→  private static final PropertyNameResolver nameResolver = new PropertyNameResolver();
    17→  private final boolean asShortForm;
    18→  private final IRI iri;
    19→
    20→  private WithIRI(String shortIRI) {
    21→    this.iri = Objects.requireNonNull(IRI.create("", shortIRI));
    22→    asShortForm = true;
    23→  }
    24→
    25→  private WithIRI(IRI iri) {
    26→    this.iri = Objects.requireNonNull(iri);
    27→    asShortForm = false;
    28→  }
    29→
    30→  @Override
    31→  public boolean test(HasIRI hasIRI) {
    32→    if (hasIRI != null) {
    33→      return asShortForm ? nameResolver.resolve(hasIRI).equals(nameResolver.resolve(iri))
    34→          : hasIRI.getIRI().equals(iri);
    35→    } else
    36→      return false;
    37→  }
    38→
    39→  public static Predicate<HasIRI> of(final String shortForm) {
    40→    return new WithIRI(shortForm);
    41→  }
    42→
    43→  public static Predicate<HasIRI> of(final IRI iri) {
    44→    return new WithIRI(nameResolver.resolve(iri));
    45→  }
    46→
    47→  public static Predicate<HasProperty> onPropertyOf(final String shortForm) {
    48→    return new Predicate<>() {
    49→      private final WithIRI withIRI = new WithIRI(shortForm);
    50→
    51→      @Override
    52→      public boolean test(HasProperty hasProperty) {
    53→        return hasProperty != null && hasProperty.getProperty() instanceof HasIRI hasIRI && withIRI.test(hasIRI);
    54→      }
    55→    };
    56→  }
    57→
    58→  public static Predicate<HasProperty> onPropertyOf(final IRI iri) {
    59→    return new Predicate<>() {
    60→      private final WithIRI withIRI = new WithIRI(iri);
    61→
    62→      @Override
    63→      public boolean test(HasProperty hasProperty) {
    64→        return hasProperty != null && hasProperty.getProperty() instanceof HasIRI hasIRI && withIRI.test(hasIRI);
    65→      }
    66→    };
    67→  }
    68→
    69→  public static <T extends OWLClassExpression> Predicate<T> onClassExpressionTypeOf(
    70→      final String shortForm) {
    71→    return new Predicate<>() {
    72→      private final WithIRI withIRI = new WithIRI(shortForm);
    73→
    74→      @Override
    75→      public boolean test(T expression) {
    76→        return expression.getClassExpressionType() instanceof HasIRI hasIRI && withIRI.test(hasIRI);
    77→      }
    78→    };
    79→  }
    80→
